INSERT INTO public.choices VALUES (509, 124, '토큰 할당량 정책이 포함된 Amazon Bedrock Guardrails 를 구현합니다. 거부된 요청에 대한 지표를 수집합니다. Amazon Bedrock Guardrails 지표를 기반으로 알림을 트리거하도록 Amazon EventBridge 규칙을 구성합니다. Amazon CloudWatch 대시보드를 사용하여 모델별 토큰 사용량 추세를 시각화합니다.', false, 1);
INSERT INTO public.choices VALUES (806, 124, '실패한 요청을 위한 Amazon SQS 데드 레터 큐를 배포합니다. 토큰 관련 오류를 분석하도록 AWS Lambda 함수를 구성합니다. Amazon CloudWatch Logs Insights 를 사용하여 Amazon Bedrock API 응답의 오류 로그를 기반으로 토큰 사용 패턴에 대한 보고서를 생성합니다.', false, 2);
INSERT INTO public.choices VALUES (701, 171, '기업이 운영하는 각 AWS 리전에 Amazon Bedrock 모델을 배포하고, Amazon Bedrock 교차 지역 모델 추론 프로필을 구성합니다. 또한, Amazon Bedrock 지식 기반을 사용하는 벡터 데이터베이스를 구성합니다.', false, 2);
INSERT INTO public.choices VALUES (547, 133, 'fmevals 또는 ragas 프레임워크를 사용하여 S3 버킷의 데이터 세트를 사용하는 평가를 실행하는 Amazon SageMaker AI 노트북 작업을 예약된 시간에 실행합니다. 노트북에 Python 코드를 작성하여 FM 에 대한 InvokeModel API 를 직접 호출하고 응답을 처리하여 평가합니다. 텍스트 생성의 실제 지식(RWK) 점수와 요약의 유해성 점수를 정확도 지표로 측정하기 위해 작업 상태 및 결과를 Amazon CloudWatch Logs 에 게시합니다. 사용자 지정 CloudWatch Logs Insights 대시보드를 생성합니다.', false, 4);
INSERT INTO public.choices VALUES (738, 180, '중앙에서 배포된 가드레일 식별자가 모델 호출에 지정되지 않은 경우 직원이 모델을 호출하지 못하도록 SCP 를 생성합니다. 각 직원의 IAM 역할에 승인된 모델만 호출할 수 있도록 권한 경계를 생성합니다.', false, 2);
INSERT INTO public.choices VALUES (807, 180, 'AWS CloudFormation 을 사용하여 차단 필터링 정책이 있는 사용자 지정 Amazon Bedrock 가드레일을 생성합니다. 스택 세트를 사용하여 조직의 각 계정에 가드레일을 배포합니다.', true, 3);
INSERT INTO public.choices VALUES (739, 180, 'AWS CloudFormation 을 사용하여 마스크 필터링 정책이 있는 사용자 지정 Amazon Bedrock 가드레일을 생성합니다. 스택 세트를 사용하여 조직의 각 계정에 가드레일을 배포합니다.', false, 4);
INSERT INTO public.choices VALUES (462, 112, '기존 SCP 를 확장하여 eu.* 추론 프로필에 대한 CRI 를 활성화합니다.', false, 4);
INSERT INTO public.choices VALUES (552, 135, '스캔한 문서에서 관련 데이터를 추출하기 위해 Amazon Textract 와 Amazon Augmented AI(Amazon A2I)를 동일 리전에 배포합니다. 신뢰도가 낮은 페이지는 담당자에게 전달합니다.', true, 0);
INSERT INTO public.choices VALUES (576, 140, '애플리케이션 프로젝트에 `rules`라는 폴더를 생성합니다. Amazon Q Developer 에서 제품 코드 제안을 참조할 수 있도록 가이드라인과 코드를 해당 폴더에 저장합니다.', false, 2);
INSERT INTO public.choices VALUES (407, 100, 'Amazon CloudWatch 대시보드를 구성하여 Amazon Bedrock API 호출에서 가져온 기본 지표를 표시합니다. 모델 출력에 기반한 사용자 지정 지표를 생성합니다. Amazon EventBridge 규칙을 설정하여 모델 응답에 대한 사후 분석을 수행하고 사용자 지정 공정성 지표를 게시하는 AWS Lambda 함수를 호출합니다.', false, 0);
INSERT INTO public.choices VALUES (408, 100, 'Amazon Bedrock Prompt Management 에서 두 가지 프롬프트 변형을 생성합니다. Amazon Bedrock Flows 를 사용하여 정의된 트래픽 할당으로 프롬프트 변형을 배포합니다. 인구통계학적 공정성을 모니터링하기 위해 콘텐츠 필터가 있는 Amazon Bedrock 가드레일을 구성합니다. 추천 불일치 임계값 위반을 감지하기 위해 InvocationsIntervened 메트릭을 사용하는 GuardrailContentSource 차원에 Amazon CloudWatch 알람을 설정합니다.', false, 1);
INSERT INTO public.choices VALUES (409, 100, '모델 출력을 분석하도록 Amazon SageMaker Clarify 를 설정합니다. 공정성 메트릭을 Amazon CloudWatch 에 게시합니다. SageMaker Clarify 편향 메트릭과 Amazon Bedrock 지연 시간 메트릭을 결합하는 CloudWatch 복합 알람을 생성하여 포괄적인 공정성 평가 대시보드를 제공합니다.', true, 2);
INSERT INTO public.choices VALUES (410, 100, '두 프롬프트 변형 간의 공정성을 비교하는 Amazon Bedrock 모델 평가 작업을 생성합니다. Amazon CloudWatch 에서 모델 호출 로깅을 활성화합니다. 각 인구통계학적 그룹에 대한 차원을 사용하여 InvocationsIntervened 메트릭에 대한 CloudWatch 알람을 설정합니다.', false, 3);
INSERT INTO public.choices VALUES (411, 101, '고위험 대화 패턴을 금지된 주제 가드레일에 추가합니다.', true, 0);
INSERT INTO public.choices VALUES (412, 101, '고위험 대화 패턴이 포함된 프롬프트를 필터링하도록 콘텐츠 필터 가드레일을 구성합니다.', false, 1);
INSERT INTO public.choices VALUES (413, 101, '경쟁사 이름이 포함된 프롬프트를 필터링하도록 콘텐츠 필터 가드레일을 구성합니다.', false, 2);
INSERT INTO public.choices VALUES (414, 101, '경쟁사 이름을 사용자 지정 단어 필터로 추가합니다. 입력 및 출력 작업을 차단으로 설정합니다.', true, 3);
INSERT INTO public.choices VALUES (415, 101, '근거 점수 임계값을 낮게 설정합니다.', false, 4);
INSERT INTO public.choices VALUES (416, 101, '근거 점수 임계값을 높게 설정합니다.', true, 5);
INSERT INTO public.choices VALUES (417, 102, 'AWS Amplify AI Kit 을 사용하여 GraphQL API 에서 스트리밍 응답을 구현하고 클라이언트 측 렌더링을 최적화합니다.', true, 0);
INSERT INTO public.choices VALUES (418, 102, 'Lambda 리졸버의 타임아웃 값을 늘립니다. 지수 백오프를 사용하는 재시도 로직을 구현합니다.', false, 1);
INSERT INTO public.choices VALUES (419, 102, '애플리케이션을 업데이트하여 API 요청을 Amazon SQS 큐로 보냅니다. AWS AppSync 리졸버를 업데이트하여 큐를 폴링하고 처리합니다.', false, 2);
INSERT INTO public.choices VALUES (420, 102, 'RetrieveAndGenerate API 를 InvokeModelWithResponseStream API 로 변경합니다. 스트리밍 응답을 지원하기 위해 Amazon API Gateway WebSocket API 를 사용하도록 애플리케이션을 업데이트합니다.', false, 3);
INSERT INTO public.choices VALUES (421, 103, '환경 변수를 사용하여 라우팅 규칙과 Amazon Bedrock FM ID 를 저장하는 AWS Lambda 함수를 배포합니다. 비즈니스 요구 사항이 변경될 때 Lambda 콘솔을 사용하여 환경 변수를 업데이트합니다. 요청 매개변수를 읽어 라우팅 결정을 내릴 수 있도록 Amazon API Gateway REST API 를 구성합니다.', false, 0);
INSERT INTO public.choices VALUES (422, 103, '요청 속성을 기반으로 라우팅 로직을 구현하는 Amazon API Gateway REST API 요청 변환 템플릿을 배포합니다. Amazon Bedrock FM 엔드포인트를 REST API 스테이지 변수로 저장합니다. 시스템이 모델 간에 전환될 때 변수를 업데이트합니다.', false, 1);
INSERT INTO public.choices VALUES (423, 103, '각 사용자 요청에 대해 AWS AppConfig 에이전트에서 라우팅 구성을 가져오도록 AWS Lambda 함수를 구성합니다. Lambda 함수에서 비즈니스 로직을 실행하여 각 요청에 적합한 함수 모듈(FM)을 선택합니다. 단일 Amazon API Gateway REST API 엔드포인트를 통해 FM 을 노출합니다.', true, 2);
INSERT INTO public.choices VALUES (424, 103, 'AWS AppConfig 에 저장된 라우팅 규칙을 평가하기 위해 Amazon API Gateway REST API 용 AWS Lambda 권한 부여기를 사용합니다. 비즈니스 로직에 따라 권한 부여 컨텍스트를 반환합니다. 각 Amazon Bedrock FM 에 대해 모델별 Lambda 함수로 요청을 라우팅합니다.', false, 3);
INSERT INTO public.choices VALUES (425, 104, 'Amazon Bedrock 프롬프트 관리를 사용하여 재사용 가능한 템플릿과 사업부별 프롬프트 변형을 구성합니다. 금지된 콘텐츠를 차단하기 위해 카테고리 필터와 민감한 용어 목록이 포함된 Amazon Bedrock 가드레일을 적용합니다.', true, 0);
INSERT INTO public.choices VALUES (426, 104, 'Amazon Bedrock Prompt Management 를 사용하여 기본 템플릿을 정의합니다. 시스템 프롬프트 변수를 사용하여 비즈니스 부서별 어조를 적용합니다. 대상 고객 기반 임계값 조정을 적용하도록 Amazon Bedrock 가드레일을 구성합니다. 내부 관리 API 를 사용하여 가드레일을 관리합니다.', false, 1);
INSERT INTO public.choices VALUES (427, 104, 'API 호출에서 비즈니스 부서 기반 지침 주입과 함께 Amazon Bedrock 을 사용합니다. 응답 형식 규칙을 Amazon DynamoDB 에 저장합니다. AWS Step Functions 를 사용하여 응답의 유효성을 검사합니다. GenAI 어시스턴트가 응답을 생성한 후 Amazon Comprehend 를 사용하여 콘텐츠 필터를 적용합니다.', false, 2);
INSERT INTO public.choices VALUES (428, 104, 'Amazon DynamoDB 에 저장된 사용자 지정 프롬프트 템플릿과 함께 Amazon Bedrock 을 사용합니다. 비즈니스 부서별 프롬프트를 선택하는 AWS Lambda 함수를 하나 생성합니다. 응답에서 금지된 콘텐츠를 필터링하기 위해 Amazon Comprehend 를 호출하는 두 번째 Lambda 함수를 생성합니다.', false, 3);
INSERT INTO public.choices VALUES (429, 105, 'Amazon OpenSearch Serverless 를 사용하여 벡터 검색 기능과 메타데이터 필터링을 제공합니다. Amazon Bedrock Knowledge Bases 에 연결하여 Anthropic Claude 기반 모델(FM)을 사용하는 검색 증강 생성(RAG) 기능을 활성화합니다.', true, 0);
INSERT INTO public.choices VALUES (430, 105, 'pgvector 확장 기능을 사용하여 Amazon Aurora PostgreSQL 데이터베이스를 배포합니다. 임베딩과 메타데이터를 저장할 테이블을 정의합니다. SQL 쿼리를 사용하여 유사성 검색을 수행합니다. 검색된 문서를 Amazon Bedrock 으로 전송하여 응답을 생성합니다.', false, 1);
INSERT INTO public.choices VALUES (431, 105, 'Amazon S3 Vectors 를 사용하여 벡터 인덱스와 필터링 불가능한 메타데이터 필드를 구성합니다. S3 Vectors 를 Amazon Bedrock 과 통합하여 검색 증강 생성(RAG) 기능을 활성화합니다.', false, 2);
INSERT INTO public.choices VALUES (432, 105, 'Amazon Neptune Analytics 그래프 데이터베이스를 설정합니다. 문서 임베딩을 저장하기에 적절한 차원의 벡터 인덱스를 구성합니다. Amazon Bedrock 을 사용하여 그래프 기반 검색을 수행하고 응답을 생성합니다.', false, 3);
INSERT INTO public.choices VALUES (433, 106, '벡터 유사도와 키워드 일치를 결합하여 의미 이해도와 정확한 용어 및 약어 일치도를 향상시키는 하이브리드 검색을 구성합니다.', true, 0);
INSERT INTO public.choices VALUES (434, 106, '벡터 임베딩의 차원을 384 에서 1536 으로 늘립니다. 검색 후 관련성이 없는 결과를 필터링하기 위해 AWS Lambda 후처리 함수를 사용합니다.', false, 1);
INSERT INTO public.choices VALUES (435, 106, 'OpenSearch Service 를 Amazon Kendra 로 교체합니다. 전처리 단계에서 쿼리 확장을 사용하여 의학 약어 및 용어 변형을 처리합니다.', false, 2);
INSERT INTO public.choices VALUES (436, 106, '초기 벡터 검색 결과를 Amazon SageMaker AI 에서 호스팅되는 머신러닝 모델로 재순위화하는 2 단계 검색 아키텍처를 구현합니다.', false, 3);
INSERT INTO public.choices VALUES (437, 107, '애플리케이션 계정에서 Amazon Bedrock 런타임용 인터페이스 VPC 엔드포인트를 생성합니다. Lambda 함수는 프라이빗 서브넷에서 실행합니다. 추론 및 데이터 플레인 정책에 IAM 조건을 사용하여 승인된 엔드포인트 및 역할에 대한 호출만 허용합니다. 데이터 스토리지 계정에서 AWS Lake Formation 의 LF 태그 기반 액세스 제어를 사용하여 테이블 및 열 수준의 계정 간 권한을 생성합니다.', true, 0);
INSERT INTO public.choices VALUES (438, 107, 'Lambda 함수를 프라이빗 서브넷에서 실행합니다. Amazon Bedrock 및 데이터 레이크에 대한 액세스를 제공하도록 NAT 게이트웨이를 구성합니다. S3 버킷 정책 및 ACL 을 사용하여 권한을 관리합니다. AWS CloudTrail 로그를 Amazon S3 로 내보내 주간 검토를 수행합니다.', false, 1);
INSERT INTO public.choices VALUES (439, 107, '애플리케이션 계정에 Amazon S3 전용 게이트웨이 엔드포인트를 생성합니다. 공용 엔드포인트를 통해 Amazon Bedrock 을 호출합니다. AWS Lake Formation 에서 데이터베이스 수준 권한을 사용하여 데이터 액세스를 관리합니다. AWS CloudTrail 로그를 Amazon CloudWatch Logs 로 스트리밍합니다. 메트릭 필터 또는 알람을 설정하지 않습니다.', false, 2);
INSERT INTO public.choices VALUES (440, 107, '애플리케이션 계정에서 VPC 엔드포인트를 사용하여 Amazon Bedrock 및 Amazon S3 에 대한 액세스를 제공합니다. IAM 경로 기반 정책만 사용하여 데이터 레이크 액세스를 관리합니다. AWS CloudTrail 로그를 Amazon CloudWatch Logs 로 전송합니다. 주기적으로 대시보드를 생성하고 설정 시간을 줄이기 위해 리전 간 읽기에 대한 공용 대체 기능을 허용합니다.', false, 3);
INSERT INTO public.choices VALUES (441, 108, 'Amazon Bedrock Studio 프롬프트 템플릿을 구성합니다. Amazon CloudWatch 를 사용하여 프롬프트 사용량 지표를 표시하는 대시보드를 생성합니다. 콘텐츠 승인 상태를 Amazon DynamoDB 에 저장합니다. AWS Lambda 함수를 사용하여 승인을 시행합니다.', false, 0);
INSERT INTO public.choices VALUES (442, 108, 'Amazon Bedrock Prompt Management 를 사용하여 버전 관리를 구현합니다. 감사 로깅을 위해 AWS CloudTrail 을 구성합니다. IAM 정책을 사용하여 승인 권한을 제어합니다. 변수를 지정하여 매개변수화된 프롬프트 템플릿을 생성합니다.', true, 1);
INSERT INTO public.choices VALUES (443, 108, 'AWS Step Functions 를 사용하여 승인 워크플로를 생성합니다. 프롬프트를 Amazon S3 에 문서로 저장합니다. 태그를 사용하여 버전 관리를 구현합니다. Amazon EventBridge 를 사용하여 알림을 보냅니다.', false, 2);
INSERT INTO public.choices VALUES (444, 108, 'Amazon S3 에 저장된 프롬프트 템플릿을 사용하여 Amazon SageMaker Canvas 를 배포합니다. AWS CloudFormation 을 사용하여 버전 관리를 구현합니다. AWS Config 를 사용하여 승인 정책을 적용합니다.', false, 3);
INSERT INTO public.choices VALUES (445, 109, 'AWS Lambda 통합을 사용하여 Amazon API Gateway WebSocket API 를 구성합니다. WebSocket API 가 Amazon Bedrock 의 InvokeModelWithResponseStream API 를 호출하고 WebSocket 연결을 통해 부분 응답을 스트리밍하도록 구성합니다.', true, 0);
INSERT INTO public.choices VALUES (446, 109, 'AWS Lambda 통합을 사용하여 Amazon API Gateway REST API 를 구성합니다. REST API 가 Amazon Bedrock 표준 InvokeModel API 를 호출하고 프런트엔드 클라이언트 측에서 100ms 마다 전체 응답 청크를 폴링하도록 구성합니다.', false, 1);
INSERT INTO public.choices VALUES (447, 109, '중간 게이트웨이 또는 프록시 계층 없이 IAM 사용자 자격 증명과 InvokeModelWithResponseStream API 를 사용하여 프런트엔드 클라이언트가 Amazon Bedrock 에 직접 연결하도록 구현합니다.', false, 2);
INSERT INTO public.choices VALUES (448, 109, 'AWS Lambda 통합을 사용하여 Amazon API Gateway HTTP API 를 구성합니다. HTTP API 가 완료된 응답을 Amazon DynamoDB 테이블에 캐시하고, 여러 페이지로 나뉜 GET 요청을 통해 프런트엔드 클라이언트에 응답을 제공하도록 구성합니다.', false, 3);
INSERT INTO public.choices VALUES (449, 110, 'Amazon Bedrock 프롬프트 관리를 사용하여 필수 입력 항목을 변수로 지정합니다. Amazon Nova Pro FM 을 선택합니다. 응답의 출력 형식을 지정합니다. 프롬프트를 플로우의 프롬프트 노드에 추가합니다.', true, 0);
INSERT INTO public.choices VALUES (450, 110, '혐오 콘텐츠 필터를 적용하는 Amazon Bedrock 가드레일을 생성합니다. 필터 응답을 차단으로 설정합니다. 가드레일을 플로우의 프롬프트 노드에 추가합니다.', false, 1);
INSERT INTO public.choices VALUES (451, 110, 'Amazon Bedrock 프롬프트 라우터를 생성합니다. Amazon Nova Pro FM 을 지정합니다. 필요한 입력값을 플로우의 입력 노드에 변수로 추가합니다. 프롬프트 라우터를 프롬프트 노드에 추가합니다. 출력 형식을 출력 노드에 추가합니다.', false, 2);
INSERT INTO public.choices VALUES (452, 110, '욕설 콘텐츠 필터를 적용하는 Amazon Bedrock 가드레일을 생성합니다. 필터 응답을 감지로 설정합니다. 가드레일을 플로우의 프롬프트 노드에 추가합니다.', true, 3);
INSERT INTO public.choices VALUES (453, 110, 'Amazon Nova Pro FM 을 지정하는 Amazon Bedrock 애플리케이션 추론 프로파일을 생성합니다. 설명에 응답 출력 형식을 지정합니다. 각 입력 변수에 태그를 포함합니다. 프로파일을 플로우의 프롬프트 노드에 추가합니다.', false, 4);
INSERT INTO public.choices VALUES (454, 111, 'Amazon Comprehend 를 사용하여 RAG 응답을 분석 및 분류하고 의료 관련 개체와 관계를 추출합니다. AWS Step Functions 를 사용하여 자동화된 평가를 오케스트레이션합니다. Amazon CloudWatch 메트릭을 구성하여 개체 인식 신뢰도 점수를 추적합니다. 정확도가 지정된 임계값 아래로 떨어지면 CloudWatch 에서 알림을 보내도록 구성합니다.', false, 0);
INSERT INTO public.choices VALUES (455, 111, '의료 콘텐츠에 맞게 세밀하게 조정된 특수 모델을 사용하여 모든 응답을 평가하는 자동화된 대규모 언어 모델(LLM) 기반 평가를 구현합니다. AWS Lambda 함수를 배포하여 평가를 병렬화합니다. 관련성 및 사실 정확도를 추적하는 Amazon CloudWatch 메트릭에 결과를 게시합니다.', false, 1);
INSERT INTO public.choices VALUES (456, 111, 'Amazon CloudWatch Synthetics 를 구성하여 정기적으로 알려진 답변이 있는 테스트 쿼리를 생성하고 모델 성공률을 추적합니다. 합성 테스트 결과를 예상 결과와 비교하는 대시보드를 설정합니다.', false, 2);
INSERT INTO public.choices VALUES (457, 111, '응답을 초기 선별하기 위해 자동화된 LLM(판정자) 평가를 사용하고, 예외적인 경우에 대해서는 담당자가 검토하는 하이브리드 평가 시스템을 배포합니다. Amazon SageMaker Feature Store 를 사용하여 평가 데이터 세트를 관리합니다. Amazon Bedrock 에 내장된 평가 기능을 사용하여 검색 정확도와 오류율을 추적합니다.', true, 3);
INSERT INTO public.choices VALUES (458, 112, 'GenAI 개발자 IAM 역할에 AdministratorAccess 정책을 추가합니다.', false, 0);
INSERT INTO public.choices VALUES (459, 112, '기존 SCP 를 확장하여 eu.amazon.nova-pro-v1:0 추론 프로필에 대해 CRI 를 활성화합니다.', true, 1);
INSERT INTO public.choices VALUES (460, 112, 'eu-west-3 리전에서 Amazon Nova Pro 에 대한 Amazon Bedrock 모델 액세스를 활성화합니다.', false, 2);
INSERT INTO public.choices VALUES (461, 112, 'GenAI 개발자 IAM 역할이 모델을 제공할 수 있는 모든 유럽 연합 AWS 리전에서 eu.amazon.nova-pro.v1:0 추론 프로필을 통해 Amazon Nova Pro 를 호출할 수 있는 권한이 있는지 확인합니다.', true, 3);
INSERT INTO public.choices VALUES (463, 113, '단일 가드레일을 구성하고 모든 범주에 대해 콘텐츠 필터를 높음으로 설정합니다. 투자 조언에 대한 차단 주제를 설정하고 차단할 샘플 문구를 포함합니다. 모든 PII 엔티티에 대해 차단 작업을 적용하는 민감 정보 필터를 설정합니다. 모든 모델 추론 호출에 가드레일을 적용합니다.', false, 0);
INSERT INTO public.choices VALUES (464, 113, '계층형 정책을 사용하여 여러 가드레일을 구성합니다. 첫 번째 가드레일을 생성하고 콘텐츠 필터를 높음으로 설정합니다. 공개 상호 작용에 대한 PII 를 차단하도록 가드레일을 구성합니다. 두 번째 가드레일을 구성하고 콘텐츠 필터를 중간으로 설정합니다. 두 번째 가드레일을 구성하여 내부 사용을 위해 개인 식별 정보(PII)를 마스킹합니다. 투자 조언을 차단하기 위해 여러 주제별 가드레일을 구성하고 문맥 근거 검사를 설정합니다.', false, 1);
INSERT INTO public.choices VALUES (465, 113, '유해 콘텐츠에 대한 가드레일을 구성하고 콘텐츠 필터를 중간 수준으로 설정합니다. 투자 조언에 대한 차단 주제를 설정하고 차단할 명확한 정의와 샘플 문구를 포함합니다. 응답에서 PII 를 마스킹하고 입력에서 금융 정보를 차단하도록 민감 정보 필터를 구성합니다. 감사를 위해 사용자 지정 차단 메시지를 사용하는 입력 및 출력 평가를 모두 활성화합니다.', true, 2);
INSERT INTO public.choices VALUES (466, 113, '각 사용 사례에 대해 별도의 가드레일을 생성합니다. 유해 콘텐츠 필터를 적용하는 가드레일을 하나 생성합니다. 투자 조언에 대한 주제 필터를 적용하는 가드레일을 생성합니다. PII 를 차단하기 위해 민감 정보 필터를 적용하는 가드레일을 생성합니다. AWS Step Functions 를 사용하여 가드레일을 순차적으로 연결합니다. 콘텐츠 분류에 기반한 조건부 논리를 사용합니다.', false, 3);
INSERT INTO public.choices VALUES (467, 114, 'Amazon Bedrock Guardrails 내에서 기반을 강화합니다. 자동 추론 검사를 활성화합니다. 프로비저닝된 처리량을 설정합니다.', false, 0);
INSERT INTO public.choices VALUES (468, 114, '프롬프트 엔지니어링을 사용하여 모델 응답을 관련 제품으로 제한합니다. InvokeModelWithResponseStream 액션과 같은 스트리밍 기술을 사용하여 고객이 체감하는 지연 시간을 줄입니다.', false, 1);
INSERT INTO public.choices VALUES (469, 114, 'Amazon Bedrock 지식 기반을 구축합니다. 검색 증강 생성(RAG)을 구현합니다. PerformanceConfigLatency 매개변수를 optimized 로 설정합니다.', true, 2);
INSERT INTO public.choices VALUES (470, 114, '제품 카탈로그 데이터를 Amazon OpenSearch Service 에 저장합니다. 모델의 제품 추천 결과를 제품 카탈로그와 비교하여 검증합니다. Amazon DynamoDB 를 사용하여 응답 캐싱을 구현합니다.', false, 3);
INSERT INTO public.choices VALUES (471, 115, 'Amazon Bedrock AgentCore 를 사용하여 메모리 및 세션 인식 추론을 관리합니다. 내장된 ID 지원, 이벤트 처리 및 관찰 기능을 갖춘 에이전트를 배포합니다.', true, 0);
INSERT INTO public.choices VALUES (472, 115, 'Amazon API Gateway 및 Amazon EventBridge 를 사용하여 Lambda 함수와 REST API 를 액션으로 등록합니다. 사용자 지정 오케스트레이션 코드 없이 Amazon Bedrock AgentCore 가 Lambda 함수와 REST API 를 호출할 수 있도록 설정합니다.', true, 1);
INSERT INTO public.choices VALUES (473, 115, 'Amazon Bedrock Agent 를 사용하여 추론 및 대화 관리를 수행합니다. AWS Step Functions 및 Amazon SQS 큐를 사용하여 오케스트레이션을 수행합니다. 단계 간 메모리 유지를 위해 에이전트 상태를 Amazon DynamoDB 에 저장합니다.', false, 2);
INSERT INTO public.choices VALUES (474, 115, '추론 로직을 Amazon API Gateway 뒤의 Amazon ECS 에 컨테이너로 배포합니다. 메모리 데이터와 ID 데이터는 Amazon Aurora 에 저장합니다.', false, 3);
INSERT INTO public.choices VALUES (475, 115, 'Amazon Kendra 와 Amazon Bedrock 을 사용하여 사용자 지정 RAG 파이프라인을 구축합니다. 도구 호출은 AWS Lambda 를 사용하여 오케스트레이션합니다. 에이전트 상태는 Amazon S3 에 저장합니다.', false, 4);
INSERT INTO public.choices VALUES (476, 116, 'Amazon Bedrock Knowledge Bases 와 Graph RAG, 그리고 Amazon Neptune Analytics 를 사용하여 금융 데이터를 저장합니다. 엔티티 간의 다중 홉 관계를 분석하고 문서 전반에 걸쳐 관련 정보를 자동으로 식별합니다.', true, 0);
INSERT INTO public.choices VALUES (477, 116, 'Amazon Bedrock Knowledge Bases 와 Amazon OpenSearch Service 벡터 스토어를 사용하여 AWS Lambda 함수를 통해 여러 벡터 임베딩을 순차적으로 조회하는 사용자 지정 관계 식별 로직을 구현합니다.', false, 1);
INSERT INTO public.choices VALUES (478, 116, 'k-최근접 이웃(k-NN) 검색을 사용하는 Amazon OpenSearch 서버리스 벡터 데이터베이스를 사용합니다. Amazon EC2 Auto Scaling 그룹에서 실행되는 애플리케이션 계층에 수동 관계 매핑을 구현합니다.', false, 2);
INSERT INTO public.choices VALUES (479, 116, 'Amazon DynamoDB 를 사용하여 사용자 지정 인덱싱 시스템에 재무 데이터를 저장합니다. 입력 질문을 기반으로 관련 레코드를 쿼리하는 AWS Lambda 함수를 사용합니다. 응답을 생성하는 Amazon SageMaker AI 를 사용합니다.', false, 3);
INSERT INTO public.choices VALUES (480, 117, 'Amazon CloudWatch 알람을 구성하여 InputTokenCount 및 OutputTokenCount 메트릭을 모니터링하고 이상 징후를 감지합니다. 모델 호출 로그를 Amazon S3 버킷에 저장합니다. AWS Glue 및 Amazon Athena 를 사용하여 잠재적인 오류 징후를 식별합니다.', false, 0);
INSERT INTO public.choices VALUES (481, 117, 'LLM 기반 판단을 사용하는 Amazon Bedrock 평가 작업을 실행하여 오류 징후를 감지합니다. Amazon CloudWatch 를 구성하여 토큰 사용량을 추적합니다. CloudWatch 메트릭을 처리하는 AWS Lambda 함수를 생성합니다. Lambda 함수가 사용 패턴 알림을 전송하도록 구성합니다.', false, 1);
INSERT INTO public.choices VALUES (482, 117, 'Amazon Bedrock 을 구성하여 모델 호출 로그를 Amazon S3 버킷에 저장합니다. 텍스트 출력 로깅을 활성화합니다. Amazon Bedrock 가드레일을 구성하여 컨텍스트 접지 검사를 실행하여 오류를 감지합니다. 토큰 사용량 지표에 대한 Amazon CloudWatch 이상 감지 알람을 생성합니다.', true, 2);
INSERT INTO public.choices VALUES (483, 117, 'AWS CloudTrail 을 사용하여 모든 Amazon Bedrock API 호출을 로깅합니다. Amazon QuickSight 에서 사용자 지정 대시보드를 생성하여 토큰 사용 패턴을 시각화합니다. Amazon SageMaker Model Monitor 를 사용하여 생성된 요약의 품질 편차를 감지합니다.', false, 3);
INSERT INTO public.choices VALUES (484, 118, 'AWS Lake Formation 을 사용하여 데이터 소스를 카탈로그화하고 접근을 제어합니다. Amazon S3 에 직접 메타데이터 태그를 적용합니다. AWS CloudTrail 을 사용하여 API 활동을 모니터링합니다.', false, 0);
INSERT INTO public.choices VALUES (485, 118, 'AWS Glue Data Catalog 를 사용하여 데이터 소스를 등록하고 태그를 지정합니다. Amazon CloudWatch Logs 를 사용하여 접근 패턴 및 애플리케이션 동작을 모니터링합니다.', false, 1);
INSERT INTO public.choices VALUES (486, 118, '데이터를 Amazon S3 에 저장하고 객체 태깅을 사용하여 출처를 식별합니다. AWS Glue Data Catalog 를 사용하여 스키마 정보를 관리합니다. AWS CloudTrail 을 사용하여 S3 버킷에 대한 접근 로그를 기록합니다.', false, 2);
INSERT INTO public.choices VALUES (487, 118, 'AWS Glue Data Catalog 를 사용하여 모든 데이터 소스를 등록합니다. 메타데이터 태그를 적용하여 데이터 소스의 출처를 식별합니다. AWS CloudTrail 을 사용하여 서비스 전반에 걸쳐 접근 및 활동 로그를 기록합니다.', true, 3);
INSERT INTO public.choices VALUES (488, 119, '프로비저닝된 동시 실행 용량을 가진 AWS Lambda 함수를 사용하여 각 분석 유형을 순차적으로 처리합니다. Lambda 함수의 시간 초과를 10 초로 설정하고, 지수 백오프를 사용하여 자동 재시도를 구성합니다.', false, 0);
INSERT INTO public.choices VALUES (489, 119, '병렬 상태를 사용하는 AWS Step Functions 를 사용하여 각 분석 유형에 대해 별도의 AWS Lambda 함수를 동시에 호출합니다. Amazon Bedrock 클라이언트 시간 초과를 구성하고, Amazon CloudWatch 메트릭을 사용하여 실행 시간과 모델 추론 지연 시간을 추적합니다.', true, 1);
INSERT INTO public.choices VALUES (490, 119, '분석 요청을 버퍼링하기 위해 Amazon SQS 큐를 생성합니다. 예약된 동시 실행 용량을 가진 여러 AWS Lambda 함수를 배포합니다. 각 Lambda 함수가 각 보고서의 서로 다른 측면을 순차적으로 처리하도록 구성한 다음 결과를 결합합니다.', false, 2);
INSERT INTO public.choices VALUES (491, 119, '각 보고서를 순차적으로 처리하는 컨테이너를 실행하는 Amazon ECS 클러스터를 배포합니다. 로드 밸런서를 사용하여 배치 워크로드를 분산합니다. 수요 변동을 처리하기 위해 CPU 사용률 기반의 자동 확장 정책을 구성합니다.', false, 3);
INSERT INTO public.choices VALUES (492, 120, '프롬프트 주입 공격을 방지하기 위해 콘텐츠 필터를 사용하도록 Amazon Bedrock 가드레일을 구성합니다. 콘텐츠 필터 수준을 높음으로 설정합니다. 가드레일 프로필을 사용하여 리전 간 가드레일 추론을 구현합니다. 자세한 가드레일 개입 이벤트를 캡처하기 위해 사용자 지정 메트릭이 있는 Amazon CloudWatch Logs 를 사용합니다.', true, 0);
INSERT INTO public.choices VALUES (493, 120, '프롬프트 주입 공격을 방지하기 위해 콘텐츠 필터를 사용하도록 Amazon Bedrock 가드레일을 구성합니다. 콘텐츠 필터 수준을 높음으로 설정합니다. 의심스러운 입력을 차단하기 위해 AWS WAF 를 사용합니다. 감사 목적으로 API 호출을 로깅하기 위해 AWS CloudTrail 을 사용합니다.', false, 1);
INSERT INTO public.choices VALUES (494, 120, '프롬프트 주입 공격을 탐지하기 위해 Amazon Comprehend 사용자 지정 분류를 배포합니다. 요청의 유효성을 검사하기 위해 Amazon API Gateway 를 사용합니다. 자세한 개입 이벤트를 캡처하기 위해 사용자 지정 메트릭이 있는 Amazon CloudWatch Logs 를 사용합니다.', false, 2);
INSERT INTO public.choices VALUES (495, 120, '유해 콘텐츠로부터 보호하기 위해 사용자 지정 콘텐츠 필터를 사용하도록 Amazon Bedrock 가드레일을 구성합니다. 콘텐츠 필터 수준을 높게 설정합니다. 알려진 공격 패턴으로부터 보호하기 위해 단어 필터를 사용합니다. 장애 조치 기능을 제공하기 위해 리전 간 가드레일 복제를 구성합니다. 규정 준수 감사를 위해 로그를 AWS CloudTrail 에 저장합니다.', false, 3);
INSERT INTO public.choices VALUES (496, 121, '프로비저닝된 처리량을 사용하는 Amazon Bedrock 을 이용하여 모델 버전을 호스팅합니다. 새 모델 버전이 출시될 때 AWS Step Functions 워크플로를 호출하도록 Amazon EventBridge 규칙을 구성합니다. 워크플로를 구성하여 트래픽을 단계적으로 전환하고, 지정된 시간 동안 대기한 후, AWS Lambda 함수를 호출하여 Amazon CloudWatch 성능 지표를 확인합니다. 지표가 임계값을 충족하면 트래픽을 증가시키고, 성능 지표가 임계값 이하로 떨어지면 트래픽 롤백을 트리거하도록 워크플로를 구성합니다.', true, 0);
INSERT INTO public.choices VALUES (497, 121, 'AWS Lambda 함수를 사용하여 다양한 Amazon Bedrock 모델 버전을 호출합니다. Amazon API Gateway HTTP API 를 스테이지 변수 및 가중치 라우팅과 함께 사용하여 트래픽을 새 모델 버전으로 점진적으로 전환합니다. Amazon CloudWatch 를 사용하여 성능 지표를 모니터링합니다. 외부 로직을 사용하여 모델 버전 간 트래픽을 조정하고 성능이 임계값 아래로 떨어지면 롤백합니다.', false, 1);
INSERT INTO public.choices VALUES (498, 121, 'Amazon SageMaker AI 엔드포인트 변형을 사용하여 여러 Amazon Bedrock 모델 버전을 나타냅니다. 변형 가중치를 사용하여 트래픽을 전환합니다. Amazon CloudWatch 를 사용하여 성능 지표를 모니터링합니다. SageMaker Model Monitor 를 사용하여 성능이 지정된 임계값 아래로 떨어지면 AWS Lambda 함수를 트리거하여 모델 배포를 롤백합니다. 이상 징후가 감지되면 모델 배포를 롤백하도록 Amazon EventBridge 규칙을 구성합니다.', false, 2);
INSERT INTO public.choices VALUES (499, 121, 'Amazon OpenSearch Service 를 사용하여 추론 로그를 추적합니다. OpenSearch Service 를 구성하여 AWS Systems Manager Automation 런북을 호출하고 추론 로그를 기반으로 Amazon Bedrock 모델 엔드포인트를 업데이트하여 트래픽을 전환합니다.', false, 3);
INSERT INTO public.choices VALUES (500, 122, '프로비저닝된 처리량 구성에서 모델 단위(MU) 수를 늘립니다.', false, 0);
INSERT INTO public.choices VALUES (501, 122, '모델 ID 매개변수를 CreateProvisionedModelThroughput API 가 반환하는 프로비저닝된 모델의 ARN 으로 바꿉니다.', true, 1);
INSERT INTO public.choices VALUES (502, 122, '피크 시간대에 발생하는 스로틀링 예외를 처리하기 위해 지수 백오프 재시도 로직을 추가합니다.', false, 2);
INSERT INTO public.choices VALUES (503, 122, 'InvokeModel API 대신 InvokeModelWithResponseStream API 를 사용하도록 애플리케이션을 수정합니다.', false, 3);
INSERT INTO public.choices VALUES (504, 123, '출처 표기 기능을 활성화한 Amazon Bedrock Knowledge Bases 를 사용합니다. RAG 를 사용하여 출처 문서의 관련성 임계값을 설정하고, 추론 과정과 출처 정보를 감사 목적으로 Amazon S3 에 저장합니다.', true, 0);
INSERT INTO public.choices VALUES (505, 123, 'Anthropic Claude 모델과 확장된 사고 기능을 Amazon Bedrock 과 함께 사용합니다. 사고 예산을 4,000 토큰으로 설정하고, 추론 추적 및 출처 정보를 감사 목적으로 Amazon DynamoDB 에 저장합니다.', false, 1);
INSERT INTO public.choices VALUES (506, 123, '사용자 지정 Anthropic Claude 모델을 사용하여 Amazon SageMaker AI 를 구성합니다. 모델의 추론 매개변수와 AWS Lambda 를 사용하여 응답을 처리합니다. 별도의 Amazon RDS 데이터베이스에서 출처 인용을 추가합니다.', false, 2);
INSERT INTO public.choices VALUES (507, 123, 'Amazon Bedrock 을 Anthropic Claude 모델 및 사고 연쇄 추론과 함께 사용합니다. Amazon Bedrock Knowledge Bases API 를 사용하여 사용자 지정 검색 추적을 구성합니다. Amazon CloudWatch 를 사용하여 응답 지연 시간 지표를 모니터링합니다.', false, 3);
INSERT INTO public.choices VALUES (508, 124, 'AWS Lambda 함수에서 모델별 토크나이저를 개발합니다. Amazon Bedrock 에 요청을 보내기 전에 토큰 사용량을 예측하도록 Lambda 함수를 구성합니다. Lambda 함수가 Amazon CloudWatch 에 지표를 게시하고 요청이 임계값에 근접할 때 알람을 트리거하도록 구성합니다. 비용 보고를 위해 자세한 토큰 사용량을 Amazon DynamoDB 에 저장합니다.', true, 0);
INSERT INTO public.choices VALUES (577, 140, '승인된 데이터 소스를 포함하는 Amazon Q Developer 사용자 정의를 생성합니다. 개발자가 해당 사용자 정의를 사용하여 애플리케이션을 개발하도록 합니다.', true, 3);
INSERT INTO public.choices VALUES (510, 124, 'Amazon API Gateway 를 사용하여 모든 Amazon Bedrock API 호출에 대한 프록시를 생성합니다. 미리 정의된 토큰 할당량이 있는 사용자 지정 사용량 플랜에 따라 요청 스로틀링을 구성합니다. 토큰 제한을 초과하는 요청을 거부하도록 API Gateway 를 구성합니다.', false, 3);
INSERT INTO public.choices VALUES (511, 125, '각 제품 카테고리별로 정밀하게 조정된 Amazon Bedrock Anthropic Claude 모델을 배포합니다. 각 모델을 주문 관리 API 에 연결하는 AWS Lambda 함수를 생성합니다. 대화 기록은 Amazon DynamoDB 에 저장합니다.', false, 0);
INSERT INTO public.choices VALUES (512, 125, 'Amazon Bedrock 에서 지속적인 사전 학습을 사용하여 모든 제품 문서를 처리하는 사용자 지정 모델을 생성합니다. AWS Lambda 함수를 사용하여 모델을 주문 관리 API 에 연결하는 Amazon API Gateway REST API 를 설정합니다.', false, 1);
INSERT INTO public.choices VALUES (513, 125, '컨테이너를 사용하는 Amazon SageMaker AI 를 통해 모델을 배포합니다. Amazon Kendra 를 사용하여 제품 문서를 검색합니다. AWS Step Functions 를 사용하여 주문 관리 API 호출을 오케스트레이션합니다.', false, 2);
INSERT INTO public.choices VALUES (514, 125, 'Amazon Bedrock 에이전트와 액션 그룹을 사용하여 주문 관리 API 와 통합합니다. 검색 증강 생성(RAG)을 사용하여 제품 문서를 검색할 수 있도록 Amazon Bedrock 기술 자료를 에이전트와 연결합니다. 감사 추적을 캡처하기 위해 추적 이벤트를 활성화합니다.', true, 3);
INSERT INTO public.choices VALUES (515, 126, '중간 출력을 Amazon DynamoDB 에 저장합니다. 상태 간에는 참조만 전달합니다. A. 각 에이전트의 처리 단계에 필요한 경우 DynamoDB 에서 전체 데이터를 검색하는 Map 상태를 생성합니다.', false, 0);
INSERT INTO public.choices VALUES (516, 126, '대용량 출력의 경우 입력 매개변수에 S3 버킷 URI 를 사용하도록 Amazon Bedrock 통합을 구성합니다. 순차적 유효성 검사 워크플로를 유지하면서 에이전트 단계 간에 S3 참조를 라우팅하기 위해 ResultPath 필드와 ResultSelector 필드를 사용합니다.', true, 1);
INSERT INTO public.choices VALUES (517, 126, '각 에이전트 상태로 넘어가기 전에 출력을 256KB 미만으로 압축하기 위해 AWS Lambda 함수를 사용합니다. 각 에이전트 작업에서 처리 전에 출력을 압축 해제하고 다음 상태로 전달하기 전에 결과를 압축하도록 구성합니다.', false, 2);
INSERT INTO public.choices VALUES (518, 126, '각 에이전트의 처리를 처리하기 위해 별도의 Step Functions 상태 머신을 구성합니다. 상태 머신 간의 실행 흐름을 조정하기 위해 Amazon EventBridge 를 사용합니다. 출력에 대한 S3 참조를 이벤트 데이터로 사용합니다.', false, 3);
INSERT INTO public.choices VALUES (519, 127, '레스토랑 데이터를 Amazon OpenSearch Service 로 마이그레이션합니다. 사용자 지정 분석기와 관련성 튜닝을 사용하여 요리 유형, 특징, 위치 등의 속성을 기반으로 레스토랑을 찾는 키워드 기반 검색 규칙을 구현합니다. 사용자 쿼리를 구조화된 검색 매개변수로 변환하는 Amazon API Gateway HTTP API 엔드포인트를 생성합니다.', false, 0);
INSERT INTO public.choices VALUES (520, 127, '레스토랑 데이터를 Amazon OpenSearch Service 로 마이그레이션합니다. Amazon Bedrock 의 파운데이션 모델(FM)을 사용하여 레스토랑 설명, 리뷰 및 메뉴 항목에서 벡터 임베딩을 생성합니다. 사용자가 자연어 쿼리를 제출하면 동일한 FM 을 사용하여 쿼리를 임베딩으로 변환합니다. k-최근접 이웃(k-NN) 검색을 수행하여 의미적으로 유사한 결과를 찾습니다.', true, 1);
INSERT INTO public.choices VALUES (521, 127, '레스토랑 데이터를 PostgreSQL 에 유지하고 pgvector 확장 기능을 구현합니다. Amazon Bedrock 의 파운데이션 모델(FM)을 사용하여 레스토랑 데이터에서 벡터 임베딩을 생성합니다. 벡터 임베딩을 PostgreSQL 에 직접 저장합니다. 동일한 FM 을 사용하여 자연어 쿼리를 벡터 표현으로 변환하는 AWS Lambda 함수를 생성합니다. Lambda 함수가 데이터베이스 내에서 유사성 검색을 수행하도록 구성합니다.', false, 2);
INSERT INTO public.choices VALUES (522, 127, '사용자 지정 수집 파이프라인을 사용하여 레스토랑 데이터를 Amazon Bedrock 지식 기반으로 마이그레이션합니다. 지식 기반이 레스토랑 정보에서 임베딩을 자동으로 생성하도록 구성합니다. 내장된 벡터 검색 기능을 갖춘 Amazon Bedrock Retrieve API 를 사용하여 자연어 입력을 통해 지식 기반을 직접 쿼리합니다.', false, 3);
INSERT INTO public.choices VALUES (523, 128, 'Amazon Bedrock 의 프롬프트 관리 기능을 사용하여 여러 프롬프트 변형을 생성합니다. 간단한 임상 문서를 사용하여 프롬프트를 수동으로 테스트합니다. Amazon Bedrock 콘솔을 사용하여 성능이 가장 우수한 버전을 배포합니다.', false, 0);
INSERT INTO public.choices VALUES (524, 128, '복잡한 임상 문서와 정량화 가능한 평가 지표가 포함된 테스트 스위트가 있는 코드 저장소에 프롬프트 버전 관리를 구현합니다. 자동화된 테스트 프레임워크를 사용하여 프롬프트 버전과 문서 성능 패턴을 비교합니다.', true, 1);
INSERT INTO public.choices VALUES (525, 128, '각 새 프롬프트 버전을 별도의 Amazon Bedrock API 엔드포인트에 배포합니다. 프로덕션 트래픽을 엔드포인트 간에 분산합니다. Amazon CloudWatch 를 구성하여 응답 지표와 사용자 피드백을 수집하고 자동 버전 선택을 지원합니다.', false, 2);
INSERT INTO public.choices VALUES (526, 128, 'Amazon Bedrock Flows 에서 동일한 임상 문서 입력을 여러 프롬프트 변형에 적용하는 사용자 지정 프롬프트 평가 흐름을 생성합니다. Amazon Comprehend Medical 을 사용하여 각 버전의 사실 정확도를 분석하고 점수를 매깁니다.', false, 3);
INSERT INTO public.choices VALUES (527, 129, '모델이 각 요약을 생성하기 전에 명시적인 사실 검증을 통해 단계별 추론을 요구하는 제로샷 사고 연쇄(CoT) 지침을 구현합니다.', true, 0);
INSERT INTO public.choices VALUES (528, 129, 'Amazon Bedrock 지식 기반과 함께 검색 증강 생성(RAG)을 사용합니다. 시맨틱 청킹과 튜닝된 임베딩을 적용하여 요약을 원본 콘텐츠에 기반을 둡니다. C. 환각 콘텐츠와 관련된 패턴과 일치하는 생성된 출력을 차단하도록 Amazon Bedrock 가드레일을 구성합니다.', true, 1);
INSERT INTO public.choices VALUES (529, 129, 'Amazon Bedrock 에서 온도 매개변수를 높입니다.', false, 3);
INSERT INTO public.choices VALUES (530, 129, 'Amazon Bedrock 모델이 각 전체 문서를 한 번에 요약하도록 합니다.', false, 4);
INSERT INTO public.choices VALUES (578, 141, 'Amazon Bedrock 에 대한 요청의 성능 구성에서 지연 시간 매개변수를 최적화로 설정하여 지연 시간 최적화 추론을 구성합니다. 반복적인 문의 처리를 위해 프롬프트 캐싱을 사용합니다.', true, 0);
INSERT INTO public.choices VALUES (531, 130, '애플리케이션 인프라에 Amazon CloudWatch Container Insights 를 구성합니다. 지연 시간 임계값에 대한 CloudWatch 알람을 설정합니다. CloudWatch 내장 메트릭 형식을 사용하여 토큰 수에 대한 사용자 지정 메트릭을 추가합니다. 데이터를 시각화하기 위해 CloudWatch 대시보드를 생성합니다.', false, 0);
INSERT INTO public.choices VALUES (532, 130, '애플리케이션 구성 요소를 통한 요청을 추적하기 위해 AWS X-Ray 를 구현합니다. 오류 패턴 감지를 위해 CloudWatch Logs Insights 를 활성화합니다. Amazon Bedrock 에 대한 모든 API 호출을 모니터링하기 위해 AWS CloudTrail 을 설정합니다. Amazon QuickSight 에서 사용자 지정 대시보드를 생성합니다.', false, 1);
INSERT INTO public.choices VALUES (533, 130, '애플리케이션 리소스에 대해 Amazon CloudWatch Application Insights 를 활성화합니다. 요청 유형 및 사용자 세그먼트에 대한 차원을 포함하는 CloudWatch 내장 메트릭 형식을 사용하여 추천 품질, 토큰 사용량 및 응답 지연 시간에 대한 사용자 지정 메트릭을 생성합니다. 모델 메트릭에 대해 CloudWatch 이상 탐지를 구성합니다. CloudWatch Logs Insights 를 사용하여 로그 패턴 분석을 수행합니다.', true, 2);
INSERT INTO public.choices VALUES (534, 130, 'Observability 플러그인이 포함된 Amazon OpenSearch Service 를 사용합니다. Amazon Kinesis 를 사용하여 모델 메트릭 및 로그를 수집합니다. 모델 동작 패턴을 분석하기 위해 사용자 지정 Piped Processing Language(PPL) 쿼리를 생성합니다. 실시간으로 이상 징후를 시각화하는 운영 대시보드를 구축합니다.', false, 3);
INSERT INTO public.choices VALUES (535, 131, '각 청크를 4,000 토큰으로 고정 크기 청킹하고 20%의 중복을 설정합니다. 애플리케이션 수준 로직을 사용하여 FM 의 최대 컨텍스트 윈도우인 200,000 토큰에 도달할 때까지 여러 청크를 순차적으로 연결한 후 추론 호출을 수행합니다.', false, 0);
INSERT INTO public.choices VALUES (536, 131, '상위 청크를 8,000 토큰, 하위 청크를 2,000 토큰으로 하는 계층적 청킹을 사용합니다. Amazon Bedrock Knowledge Bases 의 내장 검색 기능을 사용하여 쿼리 컨텍스트에 따라 관련 상위 청크를 자동으로 선택합니다. 의미 연속성을 유지하기 위해 중복 토큰을 구성합니다.', false, 1);
INSERT INTO public.choices VALUES (537, 131, '95%의 백분위수 임계값과 3 개의 문장 버퍼 크기를 사용하여 시맨틱 청킹을 수행합니다. Amazon Bedrock 의 RetrieveAndGenerate API 호출을 사용하여 임베딩 유사도 점수를 기반으로 가장 관련성이 높은 청크를 동적으로 선택합니다.', true, 2);
INSERT INTO public.choices VALUES (538, 131, 'FM 의 토크나이저를 사용하여 문서 토큰 수를 분석하는 전처리 AWS Lambda 함수를 생성합니다. Lambda 함수가 컨텍스트 윈도우의 80%에 맞는 동일한 세그먼트로 문서를 분할하도록 구성합니다. Lambda 함수가 결과를 집계하기 전에 각 세그먼트를 독립적으로 처리하도록 구성합니다.', false, 3);
INSERT INTO public.choices VALUES (539, 132, '대규모의 복잡한 추론 모델을 Amazon Bedrock 에 배포합니다. 프로비저닝된 처리량을 구매하고 배치 처리에 최적화합니다.', false, 0);
INSERT INTO public.choices VALUES (540, 132, '저지연 실시간 최적화 모델을 Amazon Bedrock 에 배포합니다. 프로비저닝된 처리량을 구매하고 자동 확장 정책을 설정합니다.', true, 1);
INSERT INTO public.choices VALUES (541, 132, '전용 GPU 인스턴스를 사용하는 Amazon SageMaker AI 실시간 엔드포인트에 대규모 언어 모델(LLM)을 배포합니다.', false, 2);
INSERT INTO public.choices VALUES (542, 132, '배치 처리에 최적화된 Amazon SageMaker AI 서버리스 엔드포인트에 중간 규모의 언어 모델을 배포합니다.', false, 3);
INSERT INTO public.choices VALUES (543, 133, '데이터 세트를 Amazon S3 버킷으로 가져옵니다. 평가 작업이 데이터 세트에 액세스할 수 있도록 적절한 IAM 권한과 CORS(교차 출처 리소스 공유) 권한을 제공합니다.', true, 0);
INSERT INTO public.choices VALUES (544, 133, '데이터 세트를 Amazon S3 버킷으로 가져옵니다. 평가 작업이 데이터 세트에 액세스할 수 있도록 적절한 IAM 권한과 VPC 엔드포인트 구성을 제공합니다.', false, 1);
INSERT INTO public.choices VALUES (545, 133, 'Amazon Bedrock 콘솔에서 예약된 시간에 모델 평가 작업을 생성하도록 AWS Lambda 함수를 구성합니다. 데이터 세트가 포함된 S3 버킷의 URI 를 입력으로 제공합니다. 텍스트 생성에 대한 실세계 지식(RWK) 점수와 요약에 대한 BERT 점수를 측정하도록 평가 작업을 구성합니다. 두 번째 Lambda 함수를 구성하여 작업 상태를 확인하고 사용자 지정 로그를 Amazon CloudWatch 에 게시합니다. 사용자 지정 Amazon CloudWatch Logs Insights 대시보드를 생성합니다.', true, 2);
INSERT INTO public.choices VALUES (546, 133, 'Amazon SageMaker Clarify 를 사용하여 예약된 시간에 모델 평가 작업을 생성합니다. 오픈 소스 프레임워크를 사용하여 표준화된 평가를 생성하고 실행합니다. 결과를 Amazon CloudWatch 네임스페이스에 게시합니다. 텍스트 생성에는 단어 오류율 점수를, 요약에는 독성도를 정확도 지표로 사용합니다. AWS Lambda 함수를 구성하여 작업 상태를 확인하고 사용자 지정 로그를 CloudWatch 에 게시합니다. 사용자 지정 Amazon CloudWatch Logs Insights 대시보드를 생성합니다.', false, 3);
INSERT INTO public.choices VALUES (548, 134, 'AWS Lambda 함수와 Amazon SQS 큐를 사용하여 AI 권장 사항에 대한 사람 검토를 위한 사용자 지정 승인 워크플로를 생성합니다. 감사 목적으로 모든 검토 결정을 Amazon DynamoDB 에 저장합니다.', false, 0);
INSERT INTO public.choices VALUES (549, 134, 'waitForTaskToken API 를 사용하여 실행을 일시 중지하는 사람 승인 단계를 포함하는 AWS Step Functions 워크플로를 생성합니다. 사람 기술자가 검토를 완료하면 AWS Lambda 함수를 사용하여 승인 결정을 포함하는 SendTaskSuccess API 를 호출합니다. 모든 검토 결정을 Amazon DynamoDB 에 저장합니다.', true, 1);
INSERT INTO public.choices VALUES (550, 134, '사람 승인 단계를 포함하는 AWS Glue 워크플로를 생성합니다. 인간 기술자의 검토 후, SendTaskSuccess API 를 호출하는 AWS Lambda 함수와 애플리케이션을 통합합니다. 모든 인간 기술자 검토 결정은 Amazon DynamoDB 에 저장합니다.', false, 2);
INSERT INTO public.choices VALUES (551, 134, '사용자 지정 이벤트 패턴으로 Amazon EventBridge 규칙을 구성하여 AI 권장 사항을 검토를 위해 인간 기술자에게 전달합니다. 인간 기술자 승인 대기열을 처리하기 위해 AWS Glue 작업을 생성합니다. 모든 인간 기술자 검토 결정을 캐시하기 위해 Amazon ElastiCache 를 사용합니다.', false, 3);
INSERT INTO public.choices VALUES (579, 141, '최대 트래픽 부하를 처리할 수 있도록 프로비저닝된 처리량과 모델 단위(MU)를 구매합니다. 반복적인 문의를 캐싱하기 위해 Amazon ElastiCache(Redis OSS)를 사용합니다.', false, 1);
INSERT INTO public.choices VALUES (553, 135, '추론 전에 제출된 문서에서 PII 를 감지하고 삭제하기 위해 AWS Lambda 함수를 사용합니다. 모델 출력에 부적절하거나 승인되지 않은 콘텐츠가 포함되지 않도록 Amazon Bedrock 가드레일을 적용합니다. 데이터 상주 요건을 시행하고 추출된 데이터에 대한 액세스를 제어하도록 리전별 IAM 역할을 구성합니다.', true, 1);
INSERT INTO public.choices VALUES (554, 135, '추론 전에 업로드된 문서에서 필드 수준 값을 의미론적으로 추출하기 위해 Amazon Kendra 및 Amazon OpenSearch Service 를 사용합니다.', false, 2);
INSERT INTO public.choices VALUES (555, 135, '업로드된 문서를 Amazon S3 에 저장하고 객체 메타데이터를 적용합니다. 각 신청자와 동일한 리전에 원본 문서를 저장하도록 IAM 정책을 구성합니다. 향후 감사를 위해 객체 태깅을 활성화합니다.', true, 3);
INSERT INTO public.choices VALUES (556, 135, 'AWS Glue Data Quality 를 사용하여 구조화된 문서 데이터의 유효성을 검사합니다. AWS Step Functions 를 사용하여 검증된 데이터를 최적화된 프롬프트로 변환하는 프롬프트 엔지니어링 단계를 포함하는 검토 워크플로를 오케스트레이션한 후 Amazon Bedrock 을 호출하여 대출 신청서를 평가합니다.', false, 4);
INSERT INTO public.choices VALUES (557, 135, 'Amazon Bedrock 의 모델 점수 결정에 기반하여 공정성 및 편향 보고서를 생성하기 위해 Amazon SageMaker Clarify 를 사용합니다.', false, 5);
INSERT INTO public.choices VALUES (558, 136, '각 부서 폴더에 acl.json 이라는 JSON 파일을 생성합니다. 각 파일에 해당 부서 데이터에 접근할 수 있는 IAM Identity Center 그룹을 지정하는 접근 제어 항목을 생성합니다. 데이터 소스 설정의 접근 제어 섹션에서 JSON 파일의 위치를 지정합니다.', false, 0);
INSERT INTO public.choices VALUES (559, 136, 'S3 버킷 최상위 폴더에 acl.json 이라는 이름의 JSON 파일을 하나 생성합니다. 각 부서의 S3 접두사를 해당 IAM Identity Center 그룹에 매핑하는 액세스 제어 항목을 추가합니다. 데이터 소스 설정의 액세스 제어 섹션에서 JSON 파일의 위치를 지정합니다.', true, 1);
INSERT INTO public.choices VALUES (560, 136, '각 IAM Identity Center 그룹에 대해 S3 버킷의 모든 접두사에 대한 액세스를 거부하는 별도의 권한 세트를 생성합니다. 각 그룹의 권한 세트에 해당 그룹이 연결된 부서를 지정하는 StringNotEquals 조건 키를 추가합니다. 이러한 권한 세트를 Identity Center 그룹에 연결합니다.', false, 2);
INSERT INTO public.choices VALUES (561, 136, 'S3 버킷 최상위 폴더에 metadata.json 이라는 이름의 메타데이터 파일을 생성합니다. 파일에 각 부서 접두사의 S3 경로를 지정하는 AccessControlList 객체를 추가합니다. 각 부서 접두사에 액세스할 수 있는 IAM Identity Center 그룹을 지정합니다. 데이터 소스 메타데이터 설정에서 파일 위치를 참조합니다.', false, 3);
INSERT INTO public.choices VALUES (562, 137, 'Amazon Bedrock 을 Amazon Kendra 와 통합하여 승인된 문서를 검색합니다. 생성된 응답을 원본 문서와 비교하고 인용을 포함하는 사용자 지정 후처리 기능을 구현합니다.', false, 0);
INSERT INTO public.choices VALUES (563, 137, 'Amazon Bedrock 지식 기반을 배포하고 승인된 임상 원본 문서에 연결합니다. Amazon Bedrock RetrieveAndGenerate API 를 사용하여 지식 기반에서 인용 정보를 반환합니다.', true, 1);
INSERT INTO public.choices VALUES (564, 137, 'Amazon Bedrock 과 Amazon Comprehend Medical 을 사용하여 의학 엔티티를 추출합니다. 의학 용어 데이터베이스에 대한 검증 로직을 구현합니다.', false, 2);
INSERT INTO public.choices VALUES (565, 137, 'Amazon Bedrock 지식 기반에서 Retrieve API 호출과 InvokeModel API 호출을 사용하여 승인된 임상 원본 문서를 검색합니다. 검색된 원본 문서와 비교하고 출처를 명시하는 검증 로직을 구현합니다.', false, 3);
INSERT INTO public.choices VALUES (566, 138, 'Amazon Transcribe 스트리밍 API 를 사용하여 통화를 텍스트로 변환합니다. 변환된 텍스트를 Amazon Comprehend 로 전달하여 감정 분석을 수행합니다. InvokeModel API 를 사용하여 Amazon Bedrock 의 Anthropic Claude 에 결과를 전달합니다. 결과를 Amazon DynamoDB 에 저장합니다. WebSocket API 를 사용하여 결과를 표시합니다.', false, 0);
INSERT INTO public.choices VALUES (567, 138, '고객이 말하기 전에 텍스트의 일부를 제공하기 위해 부분 결과 기능을 활성화한 Amazon Transcribe 스트리밍을 사용합니다. InvokeModelWithResponseStream API 를 사용하여 텍스트 조각을 Amazon Bedrock 으로 전달합니다. Amazon API Gateway WebSocket API 를 통해 콜센터 상담원에게 응답을 스트리밍합니다.', true, 1);
INSERT INTO public.choices VALUES (568, 138, 'Amazon Transcribe 배치 처리를 사용하여 통화를 텍스트로 변환합니다. ConverseStream API 를 사용하여 완성된 녹취록을 Amazon Bedrock 의 Anthropic Claude 로 전달합니다. 콜센터 상담원이 업무용 컴퓨터에서 액세스할 수 있는 Amazon Lex 챗봇 인터페이스를 통해 응답을 반환합니다.', false, 2);
INSERT INTO public.choices VALUES (569, 138, 'AWS Lambda 함수와 함께 Amazon Transcribe 스트리밍 API 를 사용하여 각 오디오 세그먼트를 녹취합니다. InvokeModel API 를 사용하여 Amazon Bedrock 의 Amazon Titan Embeddings 모델을 호출하도록 Lambda 함수를 구성합니다. 결과를 Amazon SNS 토픽에 게시하도록 Lambda 함수를 구성합니다. 콜센터 상담원을 SNS 토픽에 구독합니다.', false, 3);
INSERT INTO public.choices VALUES (570, 139, '향상된 모니터링 도구를 활성화합니다. Amazon CloudWatch 알람을 사용하여 플랫폼으로의 트래픽을 필터링합니다. Amazon Comprehend PII 감지 기능을 사용하여 데이터를 사전 처리합니다. Amazon Comprehend PII 감지 이벤트를 모니터링하는 CloudWatch 알람을 생성합니다. Amazon Rekognition 이미지 검토 단계를 포함하는 AWS Step Functions 워크플로를 생성합니다.', false, 0);
INSERT INTO public.choices VALUES (571, 139, 'Amazon API Gateway HTTP API 와 요청 유효성 검사 템플릿을 사용하여 업로드된 콘텐츠를 Amazon S3 에 저장하기 전에 콘텐츠를 검사합니다. Amazon SageMaker AI 를 사용하여 콘텐츠를 처리한 후 처리된 콘텐츠를 Amazon Bedrock 으로 전송하는 맞춤형 콘텐츠 검토 모델을 구축합니다.', false, 1);
INSERT INTO public.choices VALUES (572, 139, '사전 인증 AWS Lambda 함수를 사용하여 콘텐츠 검토 검사를 실행하는 Amazon Cognito 사용자 풀을 생성합니다. 사용자가 플랫폼에 콘텐츠를 업로드하기 전에 Amazon Textract 를 사용하여 텍스트 콘텐츠를 필터링하고 Amazon Rekognition 을 사용하여 이미지 콘텐츠를 필터링합니다.', false, 2);
INSERT INTO public.choices VALUES (573, 139, '내장된 Amazon Bedrock 가드레일을 사용하여 콘텐츠를 필터링하는 AWS Step Functions 워크플로를 생성합니다. Amazon Comprehend PII 감지를 사용하여 콘텐츠를 사전 처리합니다. Amazon Rekognition 이미지 검토를 사용합니다.', true, 3);
INSERT INTO public.choices VALUES (574, 140, '승인된 모든 내부 라이브러리, 알고리즘 및 코드 샘플이 포함된 Git 리포지토리를 생성합니다. 이 Git 리포지토리를 로컬 애플리케이션 프로젝트의 작업 영역에 포함합니다. 개발자가 Git 리포지토리에서 제안 사항을 가져오려면 `@workspace` 컨텍스트를 사용하도록 합니다.', false, 0);
INSERT INTO public.choices VALUES (575, 140, '프로젝트 루트 폴더에 `.amazonq/rules`라는 폴더를 생성합니다. 승인된 내부 라이브러리, 알고리즘 및 코드 샘플을 해당 폴더에 추가합니다.', false, 1);
INSERT INTO public.choices VALUES (580, 141, 'Amazon Bedrock 에이전트와 사용자 지정 지식 기반을 사용하여 고객 문의를 사전 처리합니다. 트래픽 분산을 위해 리전 간 추론을 구성합니다.', false, 2);
INSERT INTO public.choices VALUES (581, 141, '사용자 지정 프롬프트 라우팅 메커니즘을 사용하여 AWS Lambda 함수를 통해 요청을 사전 처리합니다. 자주 묻는 질문을 처리하기 위해 Amazon DynamoDB 를 캐싱 계층으로 사용합니다.', false, 3);
INSERT INTO public.choices VALUES (582, 142, '기존 청킹 또는 전처리 전략을 변경하지 않고 임베딩 벡터 차원을 768 에서 4,096 으로 늘립니다.', true, 0);
INSERT INTO public.choices VALUES (583, 142, '동적 검색을 Amazon S3 에 저장된 정적인 사전 작성 요약으로 대체합니다. 컴퓨팅 요구량을 줄이고 예측 가능성을 높이기 위해 Amazon CloudFront 를 사용하여 요약을 제공합니다.', false, 1);
INSERT INTO public.choices VALUES (584, 142, '고정된 토큰 제한 대신 완전한 법률 주장, 조항 또는 섹션과 같은 의미론적 경계를 사용하도록 청킹 전략을 업데이트합니다. 새 청크 구조에 맞춰 벡터 임베딩을 다시 생성합니다.', false, 2);
INSERT INTO public.choices VALUES (585, 142, 'OpenSearch Service 에서 Amazon DynamoDB 로 마이그레이션합니다. 법률 개념에 대한 더 빠른 검색을 위해 키워드 기반 인덱스를 구현합니다.', false, 3);
INSERT INTO public.choices VALUES (586, 143, 'AWS Step Functions Express 워크플로를 사용하여 대화 흐름을 오케스트레이션합니다. AWS Lambda 함수를 호출하여 명확화 로직을 실행합니다. 대화 기록을 Amazon RDS 에 저장하고 세션 ID 를 기본 키로 사용합니다.', false, 0);
INSERT INTO public.choices VALUES (587, 143, 'AWS Step Functions Standard 워크플로를 사용하여 명확화 워크플로를 오케스트레이션합니다. 콜백 대기 패턴을 포함하여 워크플로를 관리합니다. 대화 기록을 Amazon DynamoD 에 저장합니다. 온디맨드 용량을 구매하고 서버 측 암호화를 구성합니다.', true, 1);
INSERT INTO public.choices VALUES (588, 143, 'Amazon API Gateway REST API 를 사용하여 애플리케이션을 배포하고, 사용자 요청을 AWS Lambda 함수로 라우팅하여 대화 컨텍스트를 업데이트하고 검색합니다. 대화 기록은 Amazon S3 에 저장하고 서버 측 암호화를 구성합니다. 각 상호 작용은 별도의 JSON 파일로 저장합니다.', false, 2);
INSERT INTO public.choices VALUES (589, 143, 'AWS Lambda 함수를 사용하여 Amazon Bedrock 추론 API 를 호출합니다. Amazon SQS 큐를 사용하여 명확화 단계를 오케스트레이션합니다. 대화 기록은 Amazon ElastiCache(Redis OSS) 클러스터에 저장하고, 저장 시 암호화를 구성합니다.', false, 3);
INSERT INTO public.choices VALUES (590, 144, 'Amazon SageMaker Data Wrangler 를 사용하여 데이터 흐름을 생성합니다. Amazon CloudWatch 지표 및 경보를 구성하여 데이터 품질을 모니터링합니다. 사용자 지정 AWS Lambda 함수를 사용하여 데이터를 사전 처리합니다. 처리된 데이터를 Amazon Bedrock 에 로드합니다.', false, 0);
INSERT INTO public.choices VALUES (591, 144, 'AWS Glue 크롤러를 설정하여 데이터 소스를 카탈로그화합니다. 사용자 지정 변환 스크립트를 실행하는 AWS Glue ETL 작업을 생성합니다. AWS Glue Data Quality 를 사용하여 데이터 품질을 검증하고 모니터링합니다. 처리된 데이터를 Amazon Bedrock 에 로드합니다.', true, 1);
INSERT INTO public.choices VALUES (592, 144, 'Amazon Comprehend 를 사용하여 엔티티를 추출합니다. 텍스트를 청킹하는 AWS Lambda 함수를 생성합니다. Amazon Athena 를 실행하여 데이터 품질을 쿼리하고 검증합니다. 처리된 데이터를 Amazon Bedrock 에 로드합니다.', false, 2);
INSERT INTO public.choices VALUES (593, 144, '데이터 전처리 작업을 오케스트레이션하는 AWS Step Functions 워크플로를 생성합니다. Amazon EC2 인스턴스에서 사용자 지정 코드를 실행하여 데이터를 처리합니다. Amazon SageMaker Model Monitor 를 사용하여 데이터 품질을 모니터링합니다. 처리된 데이터를 Amazon Bedrock 에 로드합니다.', false, 3);
INSERT INTO public.choices VALUES (594, 145, '벡터 유사도 향상을 위해 긴급 뉴스 콘텐츠에 특화된 도메인 적응형 모델을 사용하여 임베딩을 개선합니다.', false, 0);
INSERT INTO public.choices VALUES (595, 145, 'Amazon OpenSearch 서비스로 마이그레이션합니다. 벡터 필드와 메타데이터 필터를 사용하여 결과 검색 범위를 정의합니다.', false, 1);
INSERT INTO public.choices VALUES (596, 145, 'S3 객체 메타데이터를 인덱싱하여 Amazon Bedrock 지식 기반 내에서 메타데이터 인식 필터링을 활성화합니다.', true, 2);
INSERT INTO public.choices VALUES (597, 145, '검색 중 구조화된 메타데이터 필터링 및 문서 분류를 수행하기 위해 Amazon Q Business 인덱스로 마이그레이션합니다.', false, 3);
INSERT INTO public.choices VALUES (598, 146, 'Amazon MemoryDB 클러스터를 시작하고 Flat 알고리즘을 사용하여 인덱스를 구성합니다. 성능 지표를 기반으로 수평 확장 정책을 구성합니다.', true, 0);
INSERT INTO public.choices VALUES (599, 146, 'Amazon MemoryDB 클러스터를 시작하고 HNSW(Hierarchical Navigable Small World) 알고리즘을 사용하여 인덱스를 구성합니다. 성능 지표를 기반으로 수직 확장 정책을 구성합니다.', false, 1);
INSERT INTO public.choices VALUES (600, 146, 'Amazon Aurora PostgreSQL 클러스터를 시작하고 IVFFlat(Inverted File with Flat Compression) 알고리즘을 사용하여 인덱스를 구성합니다. 로드가 증가할 때 인스턴스 클래스가 더 큰 크기로 확장되도록 구성합니다.', false, 2);
INSERT INTO public.choices VALUES (601, 146, '역파일 플랫 압축(IVFFlat) 인덱스와 높은 프로브 값을 가진 Amazon DocumentDB 클러스터를 시작합니다. 클러스터에 대한 연결을 복제 세트로 구성하고 읽기 작업을 복제 인스턴스에 분산합니다.', false, 3);
INSERT INTO public.choices VALUES (602, 147, 'AWS Lambda 와 Amazon Comprehend 를 사용하여 파일을 병렬로 처리하고, PII 를 제거하며, Amazon Bedrock API 를 호출하여 벡터를 생성합니다. Lambda 동시 실행 제한 및 메모리 설정을 구성하여 처리량을 최적화합니다.', false, 0);
INSERT INTO public.choices VALUES (603, 147, 'AWS Glue ETL 작업을 생성하여 데이터에서 PII 감지 스크립트를 실행합니다. Amazon SageMaker Processing 을 사용하여 사전 학습된 모델을 이용해 HuggingFaceProcessor 를 실행하여 임베딩을 생성합니다. 생성된 임베딩은 Amazon OpenSearch Service 에 저장합니다.', false, 1);
INSERT INTO public.choices VALUES (604, 147, 'Amazon Comprehend 를 호출하여 개인 식별 정보(PII)를 감지하는 사용자 정의 함수(UDF)가 포함된 Apache Spark 를 실행하는 Amazon EMR 클러스터를 배포합니다. Amazon Bedrock API 를 사용하여 벡터를 생성합니다. 생성된 출력은 pgvector 확장 기능을 사용하여 Amazon Aurora PostgreSQL 에 저장합니다.', false, 2);
INSERT INTO public.choices VALUES (605, 147, 'AWS Step Functions 를 사용하여 Amazon Comprehend 로 PII 를 감지하고 Amazon Bedrock 으로 임베딩을 생성하는 워크로드를 오케스트레이션하는 데이터 처리 파이프라인을 구현합니다. 벡터를 저장하고 유사성 검색 기능을 제공하기 위해 워크플로를 Amazon OpenSearch Serverless 와 직접 통합합니다.', true, 3);
INSERT INTO public.choices VALUES (606, 148, '각 구성에 대해 AWS Systems Manager Parameter Store 에 매개변수를 생성합니다. Lambda 함수를 사용하여 매개변수 업데이트를 폴링합니다. 구성이 변경될 때 Amazon EventBridge 이벤트를 사용하여 재배포를 트리거합니다.', false, 0);
INSERT INTO public.choices VALUES (607, 148, '모델 구성을 Amazon DynamoDB 테이블에 저장합니다. 고객 등급에 따라 구성을 검색하도록 액세스 패턴을 최적화합니다. 각 요청 시작 시 DynamoDB 를 쿼리하여 사용할 모델을 결정하도록 Lambda 함수를 구성합니다.', false, 1);
INSERT INTO public.choices VALUES (608, 148, 'AWS AppConfig 를 사용하여 모델 구성을 관리합니다. 기능 플래그를 사용하여 A/B 테스트를 수행합니다. 모델 매개변수에 대한 JSON 스키마 유효성 검사 규칙을 정의합니다. AWS AppConfig 에이전트를 사용하여 Lambda 함수가 구성을 검색하도록 구성합니다.', true, 2);
INSERT INTO public.choices VALUES (609, 148, '모델 구성을 저장하기 위해 Amazon ElastiCache(Redis OSS) 클러스터를 생성합니다. 짧은 TTL 값을 설정합니다. Lambda 함수에서 사용자 지정 유효성 검사 로직을 실행합니다. Amazon CloudWatch 메트릭을 사용하여 구성 사용량을 모니터링합니다.', false, 3);
INSERT INTO public.choices VALUES (610, 149, '단일 리전에서 프로비저닝된 처리량과 충분한 모델 단위(MU)를 구매합니다. 지수 백오프를 사용하여 실패한 요청을 재시도하도록 애플리케이션을 구성합니다.', false, 0);
INSERT INTO public.choices VALUES (611, 149, 'API 오버헤드를 줄이기 위해 토큰 배치 처리를 구현합니다. 사용 가능한 리전에 트래픽을 자동으로 분산하기 위해 교차 리전 추론 프로필을 사용합니다.', true, 1);
INSERT INTO public.choices VALUES (612, 149, '각 리전에 자동 확장되는 AWS Lambda 함수를 설정합니다. 클라이언트 측 라운드 로빈 요청 분산을 구현합니다. 백업용으로 프로비저닝된 처리량 1 모델 단위(MU)를 구매합니다.', false, 2);
INSERT INTO public.choices VALUES (613, 149, '여러 리전에 걸쳐 Amazon S3 버킷을 사용하여 모든 요청에 대한 배치 추론을 구현합니다. Amazon SQS 를 사용하여 비동기 검색 프로세스를 설정합니다.', false, 3);
INSERT INTO public.choices VALUES (614, 150, 'Amazon DynamoDB Accelerator(DAX) 클러스터를 인메모리 캐시로 배포합니다. 쿼리 텍스트를 파티션 키로, 모델 응답 텍스트를 정렬 키로 지정합니다. LIKE 연산자를 사용하는 필터 표현식을 통해 캐시를 쿼리합니다.', false, 0);
INSERT INTO public.choices VALUES (615, 150, 'Amazon Bedrock 을 사용하여 고객 문의로부터 임베딩을 생성합니다. Amazon MemoryDB for Valkey 를 사용하여 벡터 임베딩과 모델 응답의 해시 세트를 저장합니다. RANGE 쿼리를 사용하여 유사한 문의와 해당 응답을 찾습니다.', false, 1);
INSERT INTO public.choices VALUES (616, 150, 'k-최근접 이웃(k-NN) 기능을 갖춘 Amazon OpenSearch Service 를 배포하여 문의-응답 텍스트 쌍을 저장합니다. 근사 k-NN 기법을 사용하여 유사한 쿼리와 응답을 찾습니다.', true, 2);
INSERT INTO public.choices VALUES (617, 150, 'Amazon DynamoDB 를 사용하여 정규화된 쿼리 텍스트에 대한 전역 보조 인덱스를 생성하여 캐싱 솔루션을 구축합니다. 들어오는 쿼리에 어간 추출을 적용합니다. 캐시된 고객 쿼리 인덱스를 쿼리합니다.', false, 3);
INSERT INTO public.choices VALUES (618, 151, 'Lambda 함수를 사용하여 MCP 서버를 호스팅합니다. AI 에이전트 Lambda 함수에 MCP 서버를 호스팅하는 Lambda 함수를 호출할 수 있는 권한을 부여합니다. AI 에이전트의 MCP 클라이언트가 MCP 서버를 비동기적으로 호출하도록 구성합니다.', false, 0);
INSERT INTO public.choices VALUES (619, 151, 'Lambda 함수를 사용하여 MCP 서버를 호스팅합니다. AI 에이전트 Lambda 함수에 MCP 서버를 호스팅하는 Lambda 함수를 호출할 수 있는 권한을 부여합니다. AI 에이전트가 MCP 서버와 함께 STDIO 전송을 사용하도록 구성합니다.', false, 1);
INSERT INTO public.choices VALUES (620, 151, 'Lambda 함수를 사용하여 MCP 서버를 호스팅합니다. Lambda 함수로 요청을 프록시하는 Amazon API Gateway HTTP API 를 생성합니다. AI 에이전트 솔루션이 Streamable HTTP 전송을 사용하여 HTTP API 를 통해 요청을 보내도록 구성합니다. Amazon Cognito 를 사용하여 OAuth 2.1 을 적용합니다.', true, 2);
INSERT INTO public.choices VALUES (621, 151, 'Lambda 레이어를 사용하여 MCP 서버를 호스팅합니다. AI 에이전트 Lambda 함수에 Lambda 레이어를 추가합니다. 에이전트 AI 솔루션이 STDIO 전송을 사용하여 MCP 서버로 요청을 보내도록 구성합니다. AI 에이전트의 MCP 구성에서 Lambda 레이어 ARN 을 명령으로 지정합니다. 사용자 자격 증명을 환경 변수로 지정합니다.', false, 3);
INSERT INTO public.choices VALUES (622, 152, '각 에이전트 뒤에 Amazon API Gateway REST API 를 정의합니다. 에이전트와 보상 Lambda 함수 호출을 관리하는 두 번째 Lambda 함수를 생성합니다. 두 번째 Lambda 함수에 재시도/폴백 메커니즘을 구성합니다.', false, 0);
INSERT INTO public.choices VALUES (623, 152, '에이전트와 보상 Lambda 함수를 실행하는 네 개의 태스크로 구성된 AWS Step Functions 상태 머신을 생성합니다. 각 태스크 단계에 대해 재시도 및 오류 처리 분기를 설정합니다.', true, 1);
INSERT INTO public.choices VALUES (624, 152, '각 에이전트에 별도의 재시도/폴백 메커니즘을 구성합니다. 에이전트 및 보상 Lambda 함수에 대한 호출을 오케스트레이션하는 두 번째 Lambda 함수를 생성합니다. 두 번째 Lambda 함수 뒤에 Amazon API Gateway REST API 를 정의합니다.', false, 2);
INSERT INTO public.choices VALUES (625, 152, '에이전트 및 보상 Lambda 함수에 대한 호출을 오케스트레이션하는 두 번째 Lambda 함수를 생성합니다. 두 번째 Lambda 함수를 실행하는 하나의 태스크가 있는 AWS Step Functions 상태 머신을 생성합니다. 태스크 단계에 대한 재시도 및 오류 처리 분기를 설정합니다.', false, 3);
INSERT INTO public.choices VALUES (626, 153, 'Amazon Bedrock Flows 에서 플로우를 생성합니다. 플로우의 시작과 끝에 S3 액션 노드를 구성하여 메시지와 모델 응답을 검색하고 저장합니다. 플로우 중간에 각 메시지를 구문 분석하는 표현식을 구성합니다. 에이전트 단계를 구성하여 구문 분석된 입력을 검토를 위해 모델로 전송합니다.', true, 0);
INSERT INTO public.choices VALUES (627, 153, 'AWS Step Functions Express 워크플로 상태 머신을 생성합니다. Amazon S3 통합 GetObject 단계를 사용하여 원본 메시지를 검색합니다. 내장 함수 Pass 단계를 사용하여 메시지를 구문 분석하고 결과를 Amazon Bedrock InvokeModel 단계로 전달합니다. 모델 응답을 S3 버킷에 저장하도록 Amazon S3 통합 PutObject 단계를 구성합니다.', false, 1);
INSERT INTO public.choices VALUES (628, 153, '액션 그룹이 있는 Amazon Bedrock 에이전트를 생성합니다. 에이전트가 통신을 구문 분석하는 방법을 정의하는 지침을 구성합니다. 액션 그룹이 S3 버킷에서 통신을 검색하고, Amazon Bedrock 모델을 호출하고, 모델 응답을 S3 버킷에 저장하도록 구성합니다.', false, 2);
INSERT INTO public.choices VALUES (629, 153, '단일 액션 그룹이 있는 Amazon Bedrock 에이전트를 생성합니다. 액션 그룹에 세 개의 AWS Lambda 함수를 구성합니다. 함수가 S3 버킷에서 통신을 검색하고, 통신을 구문 분석하고, Amazon Bedrock 모델을 호출하고, 모델 응답을 S3 버킷에 저장하도록 구성합니다.', false, 3);
INSERT INTO public.choices VALUES (630, 154, '금융 전문가가 정확성, 규정 준수 및 대화체 품질 측면에서 모든 응답을 수동으로 평가하는 파이프라인을 구성합니다. Amazon SageMaker 노트북을 사용하여 결과를 분석하고 개선 영역을 파악합니다.', false, 0);
INSERT INTO public.choices VALUES (631, 154, 'Anthropic Claude Sonnet 을 평가 모델로 사용하여 응답의 정확성과 적절성을 평가하는 Amazon Bedrock 평가를 구성합니다. 금융 정책 준수 여부를 확인하는 맞춤형 Amazon Bedrock 가드레일을 구성합니다. 중요 상호 작용으로 표시된 경우 Amazon Augmented AI(Amazon A2I) 담당자 검토를 추가합니다.', true, 1);
INSERT INTO public.choices VALUES (632, 154, '고객 서비스 상호 작용을 관리하는 Amazon Lex 봇을 생성합니다. 정적 규정 준수 데이터베이스를 기반으로 응답을 확인하는 AWS Lambda 함수를 구성합니다. 봇에서 Lambda 함수를 호출하여 응답을 확인하는 인텐트를 구성합니다. 최종 사용자 리뷰를 수집하는 인텐트를 추가합니다.', false, 2);
INSERT INTO public.choices VALUES (633, 154, 'AI 어시스턴트의 응답 패턴을 모니터링하도록 Amazon CloudWatch 를 구성합니다. 잠재적인 규정 위반에 대한 CloudWatch 알림을 구성합니다. 플래그가 지정된 상호 작용을 검토할 사람 평가자 팀을 구성합니다.', false, 3);
INSERT INTO public.choices VALUES (634, 155, '각 에이전트별로 별도의 지식 기반을 사용하여 데이터를 분리합니다. IAM 필터링을 사용하여 각 지식 기반에 대한 액세스를 제어합니다. 감독 에이전트를 배포하여 환자 문의에 대한 자연어 의도 분류를 수행합니다. 감독 에이전트가 부서별 문의에 응답하기 위해 전문 협력 에이전트로 문의를 라우팅하도록 구성합니다. 각 전문 협력 에이전트가 부서별 지식 기반을 사용하여 RAG(Retrieval Augmented Generation)를 사용하도록 구성합니다.', true, 0);
INSERT INTO public.choices VALUES (635, 155, '각 부서별로 별도의 감독 에이전트를 생성합니다. 각 부서 내 전문 분야별로 자연어 의도 분류를 수행하도록 개별 협업 에이전트를 구성합니다. 각 협업 에이전트는 부서별 지식 기반에만 통합합니다. 감독 에이전트 간에 수동 인수인계 프로세스를 구현합니다.', false, 1);
INSERT INTO public.choices VALUES (636, 155, '각 부서의 데이터를 별도의 지식 기반에 격리합니다. IAM 필터링을 사용하여 각 지식 기반에 대한 액세스를 제어합니다. 단일 범용 에이전트를 배포합니다. 범용 에이전트 내에 여러 작업 그룹을 구성하여 특정 부서 기능을 수행합니다. 범용 에이전트 지침 내에 규칙 기반 라우팅 로직을 구현합니다.', false, 2);
INSERT INTO public.choices VALUES (637, 155, '각 부서의 환자 문의에 응답하기 위해 병렬로 실행되는 여러 독립적인 감독 에이전트를 구현합니다. 각 감독 에이전트에 대해 여러 협업 에이전트를 구성합니다. 모든 에이전트를 동일한 지식 기반에 통합합니다. 외부 라우팅 로직을 사용하여 여러 감독 에이전트의 응답을 병합합니다.', false, 3);
INSERT INTO public.choices VALUES (638, 156, '하나의 AWS CDK 애플리케이션을 생성합니다. AWS CodePipeline 에서 여러 파이프라인을 생성합니다. 각 파이프라인에 각 FM 에 대한 설정을 구성합니다. aws_bedrock.ProvisionedModel.fromProvisionedModelArn() 메서드를 사용하여 Amazon Bedrock FM 을 호출하도록 애플리케이션을 구성합니다.', false, 0);
INSERT INTO public.choices VALUES (639, 156, '각 환경에 대해 별도의 AWS CDK 애플리케이션을 생성합니다. aws_bedrock.FoundationModel.fromFoundationModelId() 메서드를 사용하여 Amazon Bedrock FM 을 호출하도록 애플리케이션을 구성합니다. 각 환경별로 AWS CodePipeline 에 별도의 파이프라인을 생성합니다.', false, 1);
INSERT INTO public.choices VALUES (640, 156, 'AWS CDK 애플리케이션을 하나 생성합니다. aws_bedrock.FoundationModel.fromFoundationModelId() 메서드를 사용하여 Amazon Bedrock FM 을 호출하도록 애플리케이션을 구성합니다. AWS CodeBuild 배포 작업을 사용하는 각 환경에 대한 배포 단계를 포함하는 AWS CodePipeline 파이프라인을 생성합니다.', true, 2);
INSERT INTO public.choices VALUES (641, 156, '프로덕션 환경용 AWS CDK 애플리케이션을 하나 생성합니다. aws_bedrock.ProvisionedModel.fromProvisionedModelArn() 메서드를 사용하여 Amazon Bedrock FM 을 호출하도록 애플리케이션을 구성합니다. AWS CodePipeline 파이프라인을 생성합니다. AWS CodeBuild 배포 작업을 사용하여 프로덕션 환경에 배포하도록 파이프라인을 구성합니다. 개발 환경의 경우, 프로덕션 애플리케이션 코드를 참조하여 리소스를 수동으로 다시 생성합니다.', false, 3);
INSERT INTO public.choices VALUES (642, 157, '모든 호텔의 통합 데이터를 포함하는 단일 Amazon Bedrock Knowledge Base 를 배포합니다. AWS Lambda 함수를 구성하여 직접 API 연결을 통해 각 호텔의 PMS 데이터베이스에서 데이터를 동기화합니다. 호텔별 필터를 사용하여 AWS CloudTrail 로깅을 구현하고, 각 호텔 데이터에 대한 접근 로그를 감사합니다.', false, 0);
INSERT INTO public.choices VALUES (643, 157, '각 호텔의 PMS 데이터베이스 변경 시 호출되는 Amazon EventBridge 규칙을 생성합니다. 이 규칙을 구성하여 관리용 AWS 계정에 있는 중앙 집중식 Amazon Bedrock Knowledge Base 로 업데이트를 전송합니다. 리소스 기반 정책을 구성하여 호텔 직원에 대한 호텔별 접근 제어를 적용합니다.', false, 1);
INSERT INTO public.choices VALUES (644, 157, '다중 계정 구조에서 각 호텔별로 Amazon Bedrock 지식 기반을 하나씩 구현합니다. 실시간 객실 이용 가능 정보를 제공하기 위해 직접 데이터 수집 방식을 사용합니다. 중요도가 낮은 정보는 정기적인 동기화를 예약합니다.', true, 2);
INSERT INTO public.choices VALUES (645, 157, '여러 지식 기반을 사용하는 중앙 집중식 Amazon Bedrock 에이전트를 구축합니다. 호텔 직원의 데이터 접근을 제어하기 위해 호텔별 권한 집합을 사용하여 AWS IAM Identity Center 를 구현합니다.', false, 3);
INSERT INTO public.choices VALUES (646, 158, '활성 모델 공급자를 AWS Systems Manager 파라미터 스토어에 저장합니다. Lambda 함수가 런타임에 파라미터를 읽어 호출할 모델을 결정하도록 구성합니다.', false, 0);
INSERT INTO public.choices VALUES (647, 158, '활성 모델 공급자를 AWS AppConfig 에 저장합니다. Lambda 함수가 런타임에 구성을 읽어 호출할 모델을 결정하도록 구성합니다.', true, 1);
INSERT INTO public.choices VALUES (648, 158, 'Amazon API Gateway REST API 를 구성하여 요청을 별도의 Lambda 함수로 라우팅합니다. 각 Lambda 함수를 특정 모델 공급자로 하드코딩합니다. 통합 대상을 수동으로 전환합니다.', false, 2);
INSERT INTO public.choices VALUES (649, 158, '활성 모델 공급자를 Amazon S3 에 호스팅된 JSON 파일에 저장합니다. AWS AppConfig 를 사용하여 S3 파일을 호스팅된 구성 소스로 참조합니다. Lambda 함수가 런타임에 AppConfig 를 통해 파일을 읽어 어떤 모델을 호출할지 결정하도록 구성합니다.', false, 3);
INSERT INTO public.choices VALUES (650, 159, '모든 오류에 대해 최대 3 회 재시도하고 시도 간 1 초의 고정 지연 시간을 사용하는 표준 재시도 전략을 구현합니다. 스트리밍 응답 타임아웃은 스트림을 재시작하여 처리합니다. 세션별 토큰 사용량을 제한합니다.', false, 0);
INSERT INTO public.choices VALUES (672, 164, '최종 사용자를 위해 Amazon Kendra 쿼리 제안 기능을 활성화합니다. Amazon Bedrock 을 사용하여 검색 결과 후처리를 수행하여 문서의 의미 유사성을 파악하고 정확한 결과를 생성합니다.', false, 2);
INSERT INTO public.choices VALUES (651, 159, '지터 기반 지수 백오프와 오류율이 사전 정의된 임계값을 초과할 경우 재시도를 일시적으로 비활성화하는 회로 차단기 패턴을 사용하는 적응형 재시도 전략을 구현합니다. 청크 전달 시간 초과를 모니터링하는 스트리밍 응답 핸들러를 구현합니다. 핸들러가 성공적으로 수신된 청크를 버퍼링하고 연결이 다시 설정될 때 마지막으로 수신된 청크부터 스트리밍을 지능적으로 재개하도록 구성합니다.', true, 1);
INSERT INTO public.choices VALUES (652, 159, 'AWS SDK 를 사용하여 표준 모드에서 재시도 전략을 구성합니다. 시간 초과 예외를 처리하는 try-catch 블록으로 Amazon Bedrock API 호출을 래핑합니다. 실패한 스트리밍 요청에 대해 캐시된 완료 결과를 반환합니다. 모든 사용자에 대해 전역 토큰 제한을 적용합니다. 각 요청에 대해 지터 기반 재시도 로직과 경량 토큰 트리밍을 추가합니다. 실패 지점에서 누락된 청크만 요청하여 중단된 스트림을 재개합니다. 중복 데이터 전송을 최소화하기 위해 가장 최근 청크의 작은 메모리 버퍼를 유지합니다.', false, 2);
INSERT INTO public.choices VALUES (653, 159, 'Amazon Bedrock 클라이언트 요청 시간 초과를 30 초로 설정합니다. 클라이언트 측 부하 분산을 구현합니다. 부분 결과를 버퍼링하고 애플리케이션 성능이 저하되기 시작하면 새 요청을 중지합니다. 모든 요청에 대해 정적 토큰 사용량 제한을 설정합니다. 지수 백오프 재시도, 동적 청크 크기 조정 및 컨텍스트 인식 토큰 제한을 구성합니다.', false, 3);
INSERT INTO public.choices VALUES (654, 160, 'Amazon Macie 를 사용하여 사용자 입력 및 모델 응답에서 PII 를 감지하고 수정합니다. 프롬프트 엔지니어링 기법을 적용하여 모델이 투자 조언 주제를 다루지 않도록 합니다. AWS CloudTrail 을 사용하여 대화 로그를 캡처합니다.', false, 0);
INSERT INTO public.choices VALUES (655, 160, 'AWS Lambda 함수와 Amazon Comprehend 를 사용하여 PII 를 감지하고 수정합니다. Amazon Comprehend 토픽 모델링을 사용하여 AI 비서가 투자 조언 주제를 논의하지 않도록 합니다. Amazon CloudWatch 에서 고객 대화를 캡처하기 위한 사용자 지정 메트릭을 설정합니다.', false, 1);
INSERT INTO public.choices VALUES (656, 160, '개인 식별 정보(PII)를 감지하고 필터링하기 위해 민감한 정보 정책을 적용하도록 Amazon Bedrock 가드레일을 구성합니다. AI 어시스턴트가 투자 조언 주제를 피하도록 주제 정책을 설정합니다. Converse API 를 사용하여 모델 호출을 로깅합니다. Amazon S3 에 전송 및 이미지 로깅을 활성화합니다.', true, 2);
INSERT INTO public.choices VALUES (657, 160, '정규 표현식 제어를 사용하여 PII 패턴을 일치시킵니다. 고객에게 PII 또는 투자 조언 주제를 반환하지 않도록 프롬프트 엔지니어링 기법을 적용합니다. 모델 호출 로깅, 전송 로깅 및 이미지 로깅을 Amazon S3 에 활성화합니다.', false, 3);
INSERT INTO public.choices VALUES (658, 161, 'Amazon Bedrock 에이전트에 대한 추적을 활성화합니다. FM 이 증거를 제시하도록 구조화된 프롬프트를 구성합니다. RAG 를 활성화하기 위해 Amazon Bedrock 지식 기반을 데이터 소스와 통합합니다. 애플리케이션이 권위 있는 콘텐츠를 참조하고 인용하도록 구성합니다. 애플리케이션을 다중 가용 영역(Multi-AZ) 아키텍처에 배포합니다. Amazon API Gateway 및 AWS Lambda 함수를 사용하여 애플리케이션을 확장합니다. Amazon CloudFront 를 사용하여 지연 시간이 짧은 전송을 제공합니다.', true, 0);
INSERT INTO public.choices VALUES (659, 161, 'Amazon Bedrock 에이전트에 대한 추적을 활성화합니다. Amazon OpenSearch Service 와 사용자 지정 RAG 파이프라인을 통합하여 출처를 검색하고 인용합니다. 검색된 증거를 제시하도록 구조화된 프롬프트를 구성합니다. Amazon API Gateway REST API 뒤에 애플리케이션을 배포합니다. AWS Lambda 함수와 Amazon CloudFront 를 사용하여 애플리케이션을 확장하고 지연 시간을 줄입니다. 로그를 Amazon S3 에 저장하고 AWS CloudTrail 을 사용하여 감사 추적을 캡처합니다.', false, 1);
INSERT INTO public.choices VALUES (660, 161, 'Amazon CloudWatch 를 사용하여 지연 시간과 오류율을 모니터링합니다. 출처를 인용하기 위해 모델 프롬프트를 애플리케이션 백엔드에 직접 포함합니다. 감사를 위해 애플리케이션과 사용자 간의 상호 작용을 Amazon RDS 에 저장합니다.', false, 2);
INSERT INTO public.choices VALUES (661, 161, '생성된 응답과 지원 증거를 Amazon S3 버킷에 저장합니다. 감사를 위해 버킷에서 버전 관리를 활성화합니다. AWS Glue 를 사용하여 검색된 문서를 카탈로그화합니다. Amazon Athena 에서 검색된 문서를 처리하여 주기적인 규정 준수 보고서를 생성합니다.', false, 3);
INSERT INTO public.choices VALUES (662, 162, '문서 타임스탬프를 Amazon S3 시스템 메타데이터에 저장합니다. S3 객체 태그를 사용하여 분야 분류를 구현합니다. 사용자 정의 메타데이터를 구현하여 저자 정보를 저장합니다.', true, 0);
INSERT INTO public.choices VALUES (663, 162, '법적 보존 기능을 갖춘 S3 객체 잠금을 설정하여 문서 타임스탬프를 추적합니다. S3 객체 태그를 사용하여 저자 정보를 저장합니다. 분야 분류를 위해 S3 액세스 포인트를 구현합니다.', false, 1);
INSERT INTO public.choices VALUES (664, 162, 'S3 인벤토리 보고서를 사용하여 문서 타임스탬프를 추적합니다. S3 액세스 포인트를 생성하여 분야 분류를 구현합니다. S3 Storage Lens 대시보드에 저자 정보를 저장합니다.', false, 2);
INSERT INTO public.choices VALUES (665, 162, '사용자 정의 메타데이터를 사용하여 작성자 정보를 저장합니다. S3 객체 잠금 보존 기간을 사용하여 문서 타임스탬프를 추적합니다. S3 이벤트 알림을 사용하여 도메인 분류를 구현합니다.', false, 3);
INSERT INTO public.choices VALUES (666, 163, '각 고객이 자체 내부 데이터를 포함하는 Amazon Q Business 인덱스를 설정하도록 합니다. 각 고객이 Example Corp 를 데이터 액세스자로 지정하여 Example Corp 가 보안 API 를 사용하여 런타임에 프롬프트를 강화하는 관련 콘텐츠를 검색할 수 있도록 합니다.', true, 0);
INSERT INTO public.choices VALUES (667, 163, '각 고객별로 실시간 MCP 서버를 배포하여 모델 컨텍스트 프로토콜(MCP)을 사용한 연합 검색을 활용합니다. 프롬프트 생성 중에 실시간으로 데이터를 검색합니다.', false, 1);
INSERT INTO public.choices VALUES (668, 163, '각 고객이 Amazon Bedrock 지식 기반을 구성하도록 합니다. Example Corp 에서 프롬프트 증강을 위한 구조화된 데이터를 검색할 수 있도록 계정 간 쿼리를 허용합니다.', false, 2);
INSERT INTO public.choices VALUES (669, 163, 'Amazon Kendra 를 구성하여 고객 데이터 소스를 크롤링합니다. 생성된 인덱스를 계정 간에 공유하여 Example Corp 에서 각 고객의 Amazon Kendra 인덱스를 쿼리하여 증강 데이터를 검색할 수 있도록 합니다.', false, 3);
INSERT INTO public.choices VALUES (670, 164, 'Amazon Bedrock 지식 베이스를 기본 벡터 검색 구성으로 설정합니다. Amazon Bedrock 을 사용하여 특정 용어 및 인용문을 기반으로 법률 문서 검색을 개선하도록 쿼리를 확장합니다.', false, 0);
INSERT INTO public.choices VALUES (671, 164, 'Amazon OpenSearch 서비스를 사용하여 벡터 검색과 키워드 검색을 결합한 하이브리드 검색 아키텍처를 배포합니다. Amazon Bedrock 재순위 모델을 적용하여 결과 관련성을 최적화합니다.', true, 1);
INSERT INTO public.choices VALUES (673, 164, '벡터 검색 및 Amazon Bedrock Titan 임베딩을 사용하는 Amazon OpenSearch 서비스를 이용하여 법률 문서를 색인화하고 검색합니다. 사용자 지정 AWS Lambda 함수를 사용하여 Amazon RDS 데이터베이스에 저장된 키워드 기반 필터와 검색 결과를 병합합니다.', false, 3);
INSERT INTO public.choices VALUES (674, 165, 'Amazon CloudWatch 메트릭을 데이터 소스로 사용하여 여러 기능 모델(FM)에 걸쳐 토큰 사용 추세 및 사용 패턴을 보여주는 맞춤형 Amazon QuickSight 대시보드를 생성합니다.', false, 0);
INSERT INTO public.choices VALUES (675, 165, 'Amazon CloudWatch Logs Insights 를 사용하여 Amazon Bedrock 호출 로그를 분석하여 애플리케이션별 토큰 소비 패턴 및 사용 원인을 파악합니다. 사용량이 많은 시나리오를 식별하기 위한 맞춤형 쿼리를 생성합니다. 지속적인 모니터링을 위해 대시보드에 로그 위젯을 추가합니다.', true, 1);
INSERT INTO public.choices VALUES (676, 165, 'Amazon Bedrock 의 기본 토큰 및 호출 CloudWatch 메트릭을 결합한 맞춤형 Amazon CloudWatch 대시보드를 생성합니다. CloudWatch 알람을 설정하여 토큰 사용량 임계값을 모니터링합니다.', true, 2);
INSERT INTO public.choices VALUES (677, 165, 'Amazon Bedrock 과 Amazon Managed Grafana 의 ETL 제로 통합을 사용하여 회사 전체 FM 의 토큰 사용량 추세 및 패턴을 보여주는 대시보드를 생성합니다.', false, 3);
INSERT INTO public.choices VALUES (678, 165, 'Amazon Bedrock 모델 호출 이벤트를 캡처하도록 Amazon EventBridge 규칙을 구현합니다. 토큰 사용량 데이터를 Amazon OpenSearch Serverless 를 대상으로 하는 Amazon Data Firehose 전송 스트림으로 라우팅합니다. OpenSearch 대시보드를 사용하여 사용량 패턴을 분석합니다.', false, 4);
INSERT INTO public.choices VALUES (679, 166, 'AWS Lambda 를 사용하여 Amazon SageMaker AI 비동기 엔드포인트에 호스팅된 FM 을 호출함으로써 저지연 FM 추론을 오케스트레이션합니다.', false, 0);
INSERT INTO public.choices VALUES (680, 166, '대용량 워크로드에 대해 일관된 성능을 보장하기 위해 Amazon Bedrock 에서 프로비저닝된 처리량을 구성합니다.', true, 1);
INSERT INTO public.choices VALUES (681, 166, 'Amazon SageMaker Neo 를 사용하여 엣지 배포를 지원하는 Amazon SageMaker AI 엔드포인트에 FM 을 배포합니다. 하이브리드 배포를 지원하기 위해 AWS Lambda 를 사용하여 FM 을 오케스트레이션합니다.', true, 2);
INSERT INTO public.choices VALUES (682, 166, '예측할 수 없는 트래픽 급증을 처리하기 위해 자동 확장 기능을 갖춘 Amazon Bedrock 을 사용합니다.', false, 3);
INSERT INTO public.choices VALUES (683, 166, 'Amazon SageMaker JumpStart 를 사용하여 FM 을 호스팅하고 호출합니다.', false, 4);
INSERT INTO public.choices VALUES (684, 167, 'GenAI 애플리케이션용 Amazon API Gateway REST API 엔드포인트를 구성합니다. AWS Well-Architected Generative AI Lens 를 기반으로 공통 보안, 관찰 가능성 및 RAG 패턴을 표준화된 AWS CloudFormation 템플릿에 배포합니다. 배포 후 CloudFormation Guard 를 사용하여 각 사업부에서 정책 준수 여부를 검증합니다.', false, 0);
INSERT INTO public.choices VALUES (685, 167, 'AWS Well-Architected Generative AI Lens 를 기반으로 보안, 관찰 가능성 및 RAG 패턴을 구현하는 표준화된 AWS CloudFormation 템플릿을 생성합니다. 버전 관리를 수행하는 중앙 집중식 저장소를 구축합니다. CloudFormation Guard 를 사용하여 CI/CD 파이프라인을 통합하여 비즈니스 부서 전체에 걸쳐 일관되고 반복 가능한 배포를 시행합니다.', true, 1);
INSERT INTO public.choices VALUES (686, 167, 'AWS Service Catalog 를 사용하여 각 비즈니스 부서에 대한 표준화된 포트폴리오와 버전 관리 제품을 정의합니다. 포트폴리오를 사용하여 AWS Well-Architected Generative AI Lens 를 기반으로 보안, 관찰 가능성 및 RAG 패턴을 적용합니다. 비즈니스 부서에서 Service Catalog 콘솔을 사용하여 리소스를 배포하도록 요구합니다.', false, 2);
INSERT INTO public.choices VALUES (687, 167, '공유 설계 문서에 AWS Well-Architected Generative AI Lens 를 기반으로 한 보안 제어, 관찰 가능성 요구 사항 및 RAG 패턴을 문서화합니다. Amazon Macie 를 사용하여 배포를 시행합니다. 각 비즈니스 부서에 구현 책임을 위임합니다.', false, 3);
INSERT INTO public.choices VALUES (688, 168, '번역 작업량이 많은 워크로드를 여러 언어로 동시에 도우미에 전송하는 분산 트래픽 시뮬레이션 프레임워크를 구축합니다. Amazon CloudWatch 메트릭을 사용하여 지연 시간, 동시성 및 처리량을 모니터링합니다. 프로덕션 릴리스 전에 시뮬레이션을 실행하여 인프라 병목 현상을 파악합니다.', false, 0);
INSERT INTO public.choices VALUES (689, 168, 'Amazon Route 53 의 지연 시간 기반 라우팅 및 AWS Global Accelerator 를 사용하여 도우미를 여러 AWS 리전에 배포하여 글로벌 성능을 향상시킵니다. 다국어 대화 로그를 Amazon S3 에 저장합니다. 일관성을 검토하기 위해 배포 후 매주 감사를 수행합니다.', false, 1);
INSERT INTO public.choices VALUES (690, 168, '모든 수신 메시지를 어시스턴트로 보내기 전에 일관된 형식으로 정규화하는 전처리 파이프라인을 생성합니다. 출력에서 발생할 수 있는 오류를 표시하기 위해 규칙 기반 검사를 적용합니다. 언어 간 테스트를 단순화하기 위해 정규화된 텍스트에 대한 평가에 집중합니다.', false, 2);
INSERT INTO public.choices VALUES (691, 168, '의미가 동일한 표준화된 다국어 테스트 대화를 설정합니다. Amazon Bedrock 모델 평가 작업을 사용하여 테스트 대화를 병렬로 실행합니다. 유사성 및 오류 임계값을 적용합니다. 실패한 릴리스를 차단하기 위해 프로세스를 CI/CD 파이프라인에 통합합니다.', true, 3);
INSERT INTO public.choices VALUES (692, 169, 'Amazon CloudWatch Logs 를 사용하여 모델 호출 로그를 캡처합니다. InputTokenCount 및 OutputTokenCount 메트릭을 기반으로 CloudWatch 대시보드를 생성합니다. 각 도구 통합 기능에 대해 고정 임계값을 가진 정적 CloudWatch 알람을 구성합니다.', false, 0);
INSERT INTO public.choices VALUES (693, 169, '모델 호출 로그를 Amazon S3 버킷에 저장합니다. AWS Glue 를 사용하여 로그를 카탈로그화합니다. 도구 사용 추세에 대한 보고서를 생성하는 예약된 Amazon Athena 쿼리를 사용하여 토큰 소비 패턴을 분석합니다.', false, 1);
INSERT INTO public.choices VALUES (694, 169, 'Amazon CloudWatch Logs 를 사용하여 모델 호출 로그를 캡처합니다. CloudWatch 메트릭 필터를 생성하여 도구별 호출 패턴을 추출합니다. 각 도구의 메트릭에 대한 기준선을 조정하는 CloudWatch 이상 감지 알람을 적용합니다.', true, 2);
INSERT INTO public.choices VALUES (695, 169, '모델 호출 로그를 Amazon S3 버킷에 저장합니다. 로그를 실시간으로 처리하는 AWS Lambda 함수를 생성합니다. Lambda 함수가 식별한 토큰 소비 추세를 기반으로 Amazon CloudWatch 알람 임계값을 수동으로 업데이트합니다.', false, 3);
INSERT INTO public.choices VALUES (696, 170, '북미 및 유럽 리전에 각각 별도의 Amazon Bedrock 인스턴스를 배포합니다. 사용자 위치에 따라 트래픽을 라우팅하는 사용자 지정 라우팅 계층을 사용합니다. Amazon CloudWatch 알람을 구성하여 리전 서비스 사용량을 모니터링합니다. 사용량이 지정된 임계값에 근접할 때 회사에 이메일 알림을 보내도록 Amazon SNS 를 사용합니다.', false, 0);
INSERT INTO public.choices VALUES (697, 170, '애플리케이션이 InvokeModel API 를 호출할 때 프로필 ID 에 지리적 코드를 지정하여 Amazon Bedrock 리전 간 추론 프로필을 사용합니다. 유럽 및 북미 사용자를 적절한 지역 엔드포인트로 연결하도록 별도의 Amazon API Gateway HTTP API 를 구성합니다.', true, 1);
INSERT INTO public.choices VALUES (698, 170, '스로틀링을 처리하기 위한 재시도 로직을 구현하는 다중 리전 Amazon API Gateway HTTP API 및 AWS Lambda 함수를 배포합니다. 기본 리전에서 애플리케이션이 서비스 할당량에 도달하면 가장 가까운 보조 리전의 FM 을 호출하도록 Lambda 함수를 구성합니다. 데이터 상주 요구 사항을 준수하도록 지능형 라우팅을 사용합니다.', false, 2);
INSERT INTO public.choices VALUES (699, 170, '여러 리전에서 Amazon Bedrock 에 대한 프로비저닝된 처리량을 구성합니다. 스로틀링이 발생할 때 리전 간에 전환하도록 애플리케이션 코드에 장애 조치 로직을 구현합니다. 사용자 위치에 따라 적절한 엔드포인트로 트래픽을 라우팅하기 위해 AWS Global Accelerator 를 사용합니다.', false, 3);
INSERT INTO public.choices VALUES (700, 171, '교차 지역 모델 추론 프로필을 사용하여 Amazon Bedrock 모델을 배포합니다. 기업이 운영하는 각 AWS 리전에 Amazon S3 버킷을 생성하고, 각 S3 버킷에 지식 기반을 저장합니다. 각 리전에서 Amazon Kendra 가 해당 지식 기반과 상호 작용하도록 구성하고, Kendra 와 Amazon Bedrock 을 사용하여 AI 비서의 프롬프트를 처리하는 AWS Lambda 함수를 구성합니다.', false, 0);
INSERT INTO public.choices VALUES (702, 171, 'AWS Outposts 를 사용하여 회사가 운영하는 각 AWS 리전에 아웃포스트를 배포합니다. 해당 리전에 지식 기반을 저장할 Amazon S3 버킷을 생성합니다. 각 아웃포스트에 벡터 데이터베이스로 구성된 Amazon RDS 를 배포합니다. 중앙 리전에 교차 리전 추론 프로필이 있는 Amazon Bedrock 모델을 배포합니다.', true, 1);
INSERT INTO public.choices VALUES (703, 171, '회사가 운영하는 각 AWS 로컬 영역의 Amazon S3 Express One Zone 스토리지 클래스에 저장된 지식 기반을 구성합니다. Amazon RDS 를 사용하여 회사가 운영하는 각 로컬 영역에 벡터 데이터베이스를 배포합니다. 각 로컬 영역의 Amazon EC2 인스턴스에 대규모 언어 모델(LLM)을 배포합니다. AI 어시스턴트가 해당 로컬 영역의 모델로 프롬프트를 라우팅하도록 구성합니다.', false, 3);
INSERT INTO public.choices VALUES (704, 172, '각 환경에 대해 별도의 인증 방법을 사용하여 Amazon Bedrock InvokeModel API 를 사용합니다. 대화 상태는 Amazon DynamoDB 에 저장합니다. 각 프로그래밍 언어에 대해 사용자 지정 I/O 형식 지정 로직을 사용합니다.', false, 0);
INSERT INTO public.choices VALUES (705, 172, 'IAM 역할을 사용하는 공통 인증 메커니즘을 통해 두 환경 모두에서 Amazon Bedrock Converse API 를 직접 사용합니다. 대화 상태는 Amazon ElastiCache 에 저장합니다. 모델 매개변수에 대한 프로그래밍 언어별 래퍼를 생성합니다.', false, 1);
INSERT INTO public.choices VALUES (706, 172, 'InvokeModel API 를 사용하여 모든 모델 상호 작용을 처리하는 중앙 집중식 Amazon API Gateway REST API 엔드포인트를 생성합니다. 각 Lambda 함수 또는 EKS 컨테이너의 애플리케이션 프로세스 메모리에 상호 작용 기록을 저장합니다. 환경 변수를 사용하여 모델 매개변수를 구성합니다.', false, 2);
INSERT INTO public.choices VALUES (707, 172, 'Amazon Bedrock Converse API 및 IAM 역할을 사용하여 인증합니다. 대화 컨텍스트를 유지하기 위해 요청 메시지 배열에 이전 메시지를 전달합니다. 일관된 API 인터페이스를 구축하기 위해 프로그래밍 언어별 SDK 를 사용합니다.', true, 3);
INSERT INTO public.choices VALUES (708, 173, '모델 오류를 모니터링하기 위해 사용자 지정 Amazon CloudWatch 지표를 생성합니다. 프로비저닝된 처리량을 관찰된 피크 트래픽보다 안전하게 높은 값으로 설정합니다.', false, 0);
INSERT INTO public.choices VALUES (709, 173, '모델 오류를 모니터링하기 위해 사용자 지정 Amazon CloudWatch 지표를 생성합니다. 오류가 지정된 임계값을 초과할 경우 백업 AWS 리전으로 호출을 리디렉션하는 장애 조치 메커니즘을 설정합니다.', false, 1);
INSERT INTO public.choices VALUES (710, 173, 'Amazon Bedrock 에서 호출 로깅을 활성화합니다. 호출 횟수, 입력 토큰 수, 출력 토큰 수, 호출 스로틀링과 같은 주요 지표를 모니터링합니다. 리전 간 추론 엔드포인트에 트래픽을 분산합니다.', true, 2);
INSERT INTO public.choices VALUES (711, 173, 'Amazon Bedrock 에서 호출 로깅을 활성화합니다. InvocationLatency, InvocationClientErrors 및 InvocationServerErrors 메트릭을 모니터링합니다. 동일한 모델의 여러 버전에 트래픽을 분산합니다.', false, 3);
INSERT INTO public.choices VALUES (712, 174, 'Lambda Invoke API 를 사용하여 사용자 지정 Lambda 호출 전송을 생성합니다. IAM 인증을 구현하고 승인된 사용자 및 역할에 InvokeFunction 권한을 부여합니다.', false, 0);
INSERT INTO public.choices VALUES (713, 174, 'Amazon API Gateway REST API 엔드포인트를 통해 Lambda 함수를 노출합니다. 인증을 위해 API 키를 구현합니다. MCP 서버에 액세스해야 하는 애플리케이션이 MCP 프로토콜 대신 표준 HTTP 요청을 사용하도록 구성합니다.', false, 1);
INSERT INTO public.choices VALUES (714, 174, 'Lambda 함수 URL 을 생성하고 사용자 지정 Streamable HTTP 전송 및 SigV4 를 활성화합니다. AWS IAM 인증을 구현합니다. InvokeFunctionUrl 권한을 승인된 사용자 및 역할에 부여합니다.', false, 2);
INSERT INTO public.choices VALUES (715, 174, 'Streamable HTTP 전송을 사용하여 Amazon API Gateway HTTP API 엔드포인트를 통해 Lambda 함수를 노출합니다. Amazon Cognito 를 사용하여 OAuth 인증을 구현합니다. API Gateway 에서 OAuth 토큰을 검증하도록 구성합니다.', true, 3);
INSERT INTO public.choices VALUES (716, 175, '재시도 간 고정 지연 시간 1 초를 설정하는 사용자 지정 재시도 메커니즘을 구현합니다. Amazon CloudWatch 알람을 구성하여 애플리케이션의 오류율 및 지연 시간 지표를 모니터링합니다.', false, 0);
INSERT INTO public.choices VALUES (717, 175, '표준 재시도 모드와 지터가 있는 지수 백오프를 사용하여 AWS SDK 를 구성합니다. 주석이 포함된 AWS X-Ray 추적을 사용하여 서비스 구성 요소를 식별하고 필터링합니다.', true, 1);
INSERT INTO public.choices VALUES (718, 175, '모든 FM 응답에 대한 클라이언트 측 캐싱을 구현합니다. API 호출 시간을 기록하기 위해 애플리케이션 코드에 사용자 지정 로깅 문을 추가합니다.', false, 2);
INSERT INTO public.choices VALUES (719, 175, '적응형 재시도 모드로 AWS SDK 를 구성합니다. 스로틀링 이벤트를 모니터링하려면 AWS CloudTrail 분산 추적을 사용합니다.', false, 3);
INSERT INTO public.choices VALUES (736, 180, '각 직원의 IAM 역할에 대한 IAM 권한 경계를 생성합니다. Amazon Bedrock 모델을 호출하려면 승인된 Amazon Bedrock 가드레일 식별자가 필요하도록 권한 경계를 구성합니다. 직원들이 승인된 모델만 사용할 수 있도록 SCP 를 생성합니다.', false, 0);
INSERT INTO public.choices VALUES (720, 176, 'Amazon Bedrock 모델 API 호출을 위한 VPC 엔드포인트를 구성합니다. 프롬프트 및 응답에서 유해하거나 승인되지 않은 콘텐츠를 필터링하기 위해 Amazon Bedrock Guardrails 를 구현합니다. 감사 목적으로 모든 에이전트 및 모델 호출을 추적하기 위해 Amazon Bedrock 추적 이벤트를 사용합니다. 모델 사용에 대한 감사 기록으로 추적 데이터를 Amazon CloudWatch Logs 로 내보냅니다. 모든 프롬프트와 출력은 AWS KMS 키(SSE-KMS)를 사용한 서버 측 암호화 방식으로 Amazon S3 에 저장합니다.', false, 0);
INSERT INTO public.choices VALUES (721, 176, '속성 기반 제어를 사용하는 IAM 을 통해 부서를 특정 권한에 매핑하여 액세스 제어를 정의합니다. Amazon Bedrock 모델 API 호출을 위한 VPC 엔드포인트를 구성합니다. 특정 GuardrailIdentifier 및 ModelId 값을 적용하기 위해 IAM 조건 키를 사용합니다. AWS CloudTrail 을 구성하여 S3 객체 및 KMS 키 사용 활동에 대한 관리 및 데이터 이벤트를 캡처합니다. S3 서버 액세스 로깅을 활성화하여 비디오 아카이브와의 파일 수준 상호 작용에 대한 자세한 기록을 저장합니다. 모든 CloudTrail 로그를 AWS CloudTrail Lake 로 전송합니다. Amazon CloudWatch 알람을 설정하여 Amazon Bedrock, Amazon Rekognition 및 AWS KMS 에서 발생하는 예기치 않은 활동을 감지하고 경고합니다.', true, 1);
INSERT INTO public.choices VALUES (722, 176, 'VPC 엔드포인트 정책을 사용하여 서비스 액세스를 제한합니다. AWS Config 를 사용하여 리소스 변경 사항 및 보안 규칙 준수 여부를 추적합니다. AWS KMS 키(SSE-KMS)를 사용한 서버 측 암호화를 통해 저장된 데이터를 암호화합니다. 모델의 I/O 를 별도의 Amazon S3 버킷에 저장합니다. S3 서버 액세스 로깅을 활성화하여 파일 수준 상호 작용을 추적합니다.', false, 2);
INSERT INTO public.choices VALUES (723, 176, 'AWS CloudTrail Insights 를 구성하여 계정 전체의 API 호출 패턴을 분석하고 Amazon Bedrock, Amazon Rekognition, Amazon S3 및 AWS KMS 에서 비정상적인 활동을 감지합니다. Amazon Macie 를 배포하여 비디오 아카이브를 스캔하고 분류합니다. 저장된 모든 데이터를 암호화하기 위해 AWS KMS 키(SSE-KMS)를 사용한 서버 측 암호화를 활용합니다. 감사 목적으로 KMS API 사용 이벤트를 캡처하도록 CloudTrail 을 구성합니다. CloudTrail Insights 이상 징후 및 Macie 발견 사항을 처리하도록 Amazon EventBridge 규칙을 구성합니다. 잠재적인 보안 문제가 감지될 때 자동 알림 및 보안 대응을 트리거하도록 CloudWatch 알람을 사용합니다.', false, 3);
INSERT INTO public.choices VALUES (724, 177, 'AWS Glue 를 사용하여 업로드된 각 파일에 대해 ETL 작업을 실행합니다. ETL 작업이 AWS SDK 를 사용하여 SageMaker AI 모델 엔드포인트를 호출하도록 구성합니다. 엔드포인트에서 실시간 추론을 사용하여 업데이트된 고객 데이터 세트로 재학습된 모델을 다시 배포합니다.', false, 0);
INSERT INTO public.choices VALUES (725, 177, '직원이 새 파일을 업로드할 때 이벤트를 생성하는 AWS Lambda 함수와 웹훅 핸들러를 생성합니다. SageMaker Pipelines 를 구성하여 업데이트된 고객 데이터 세트로 재학습된 모델을 다시 배포합니다. Amazon EventBridge 를 사용하여 이벤트 버스를 생성합니다. Lambda 함수 이벤트를 소스로, SageMaker Pipelines 를 대상으로 설정합니다.', true, 1);
INSERT INTO public.choices VALUES (726, 177, 'AWS SDK 통합을 사용하여 직원이 S3 버킷에 새 파일을 업로드할 때 S3 버킷에서 고객 데이터를 검색하는 AWS Step Functions Express 워크플로를 생성합니다. SageMaker Data Wrangler 플로우를 사용하여 S3 버킷에서 SageMaker Autopilot 으로 데이터를 내보냅니다. SageMaker Autopilot 을 사용하여 업데이트된 고객 데이터 세트로 재학습된 모델을 다시 배포합니다.', false, 2);
INSERT INTO public.choices VALUES (727, 177, 'AWS Step Functions Standard 워크플로를 생성합니다. 첫 번째 상태에서 직원이 S3 버킷에 새 파일을 업로드할 때 응답하는 AWS Lambda 함수를 호출하도록 구성합니다. SageMaker Pipelines 의 파이프라인을 사용하여 업데이트된 고객 데이터 세트로 재학습된 모델을 다시 배포합니다. 워크플로의 첫 번째 상태에서 응답을 받으면 다음 상태를 사용하여 파이프라인을 실행합니다.', false, 3);
INSERT INTO public.choices VALUES (728, 178, '지원되는 버전의 Anthropic Claude Sonnet 을 평가자 모델로 사용하는 검색 전용 평가 작업을 생성합니다. 컨텍스트 관련성 및 컨텍스트 범위에 대한 메트릭을 구성합니다. 별도의 CI/CD 파이프라인에서 배포 임계값을 정의합니다.', false, 0);
INSERT INTO public.choices VALUES (729, 178, 'k 에서의 사용자 지정 정밀도 메트릭과 1~5 척도를 사용하는 LLM-as-a-judge 메트릭을 사용하는 검색 및 생성 평가 작업을 생성합니다. 평가 데이터 세트에 각 청킹 전략을 포함합니다. 지원되는 버전의 Anthropic Claude Sonnet 을 사용하여 두 FM 의 응답을 평가합니다.', true, 1);
INSERT INTO public.choices VALUES (730, 178, '각 청킹 전략과 FM 조합에 대해 별도의 평가 작업을 생성합니다. 정확성 및 완전성에 대한 Amazon Bedrock 내장 메트릭을 사용합니다. 배포 승인 전에 점수를 수동으로 검토합니다.', false, 2);
INSERT INTO public.choices VALUES (731, 178, '검색 품질을 평가하기 위해 여러 개의 검색 전용 평가 작업을 사용하는 파이프라인을 설정합니다. Amazon Nova Pro 를 LLM-as-a-judge 모델로 사용하는 두 FM 에 대해 별도의 평가 작업을 생성합니다. 충실도 및 인용 정밀도 지표를 기준으로 평가합니다.', false, 3);
INSERT INTO public.choices VALUES (732, 179, '원본 비디오를 Amazon Rekognition 에 입력하여 동물의 자세와 표정을 감지합니다. Amazon Data Firehose 를 사용하여 센서 및 GPS 데이터를 Amazon S3 데이터 레이크로 스트리밍합니다. AWS Systems Manager Parameter Store 에 저장된 기본 템플릿을 사용하여 Amazon Bedrock 기반 모델(FM)을 실행합니다. IAM 정책을 사용하여 액세스를 제어합니다. AWS CloudTrail 을 사용하여 감사 로깅을 수행합니다.', false, 0);
INSERT INTO public.choices VALUES (733, 179, 'Amazon SageMaker Processing 및 Amazon Transcribe 를 사용하여 멀티모달 데이터를 전처리합니다. 요약 정보를 Amazon Bedrock Retrieval Augmented Generation(RAG) 지식 기반에 입력합니다. Amazon Bedrock 가드레일을 적용하여 추측성 출력을 제한합니다. AWS AppConfig 를 사용하여 프롬프트 템플릿을 관리합니다. AWS CloudTrail 을 사용하여 감사를 위해 연구 활동을 기록합니다.', true, 1);
INSERT INTO public.choices VALUES (734, 179, 'Amazon OpenSearch Serverless 를 사용하여 행동 로그 및 원격 측정 이벤트를 인덱싱합니다. Amazon Comprehend 를 사용하여 엔티티를 추출합니다. Amazon Bedrock 을 사용하여 질문에 답변하는 레이어를 구축합니다. OpenSearch Serverless 문서에 학습 요약을 포함합니다. IAM 을 사용하여 액세스를 제어합니다. AWS CloudTrail 을 사용하여 AI 어시스턴트와의 사용자 상호 작용을 기록합니다.', false, 2);
INSERT INTO public.choices VALUES (735, 179, 'Amazon Q Business 를 구성하여 Amazon S3, Amazon Kinesis 및 Amazon SageMaker Feature Store 간에 데이터를 통합합니다. Amazon EventBridge 를 구성하여 데이터 수집 작업을 호출합니다. 사용자 지정 AWS Lambda 함수를 사용하여 결과를 사용자에게 반환하기 전에 윤리 규정 준수를 위해 대규모 언어 모델(LLM) 출력을 필터링합니다.', false, 3);
INSERT INTO public.choices VALUES (737, 180, '직원들이 승인된 모델만 사용할 수 있도록 SCP 를 생성합니다. 승인된 모델을 호출할 때 직원들이 가드레일 식별자를 지정하도록 SCP 를 구성합니다.', true, 1);
INSERT INTO public.choices VALUES (740, 181, 'Amazon API Gateway HTTP API 를 AWS Lambda 함수와 통합하여 Amazon Bedrock 을 호출합니다. Lambda 응답 스트리밍을 사용하여 응답을 스트리밍합니다. Lambda 함수 내에서 토큰 제한을 적용합니다. Lambda 및 API Gateway 시간 초과 구성을 사용하여 모델 시간 초과에 대한 재시도 로직을 구현합니다.', true, 0);
INSERT INTO public.choices VALUES (741, 181, 'Amazon API Gateway HTTP API 를 Amazon Bedrock 에 직접 연결합니다. 클라이언트 측 폴링을 사용하여 스트리밍을 시뮬레이션합니다. 프런트엔드에서 토큰 제한을 적용합니다. API Gateway 통합 설정을 사용하여 재시도 동작을 구성합니다.', false, 1);
INSERT INTO public.choices VALUES (742, 181, 'Amazon API Gateway WebSocket API 를 컨테이너화된 추론 서버를 호스팅하는 Amazon ECS 서비스에 연결합니다. WebSocket 프로토콜을 사용하여 응답을 스트리밍합니다. Amazon ECS 내에서 토큰 제한을 적용합니다. ECS 작업 수명 주기 후크 및 재시작 정책을 사용하여 모델 시간 초과를 처리합니다.', false, 2);
INSERT INTO public.choices VALUES (743, 181, 'Amazon Bedrock 을 호출하는 AWS Lambda 함수와 Amazon API Gateway REST API 를 통합합니다. Lambda 응답 스트리밍을 사용하여 응답을 스트리밍합니다. Lambda 함수 내에서 토큰 제한을 적용합니다. Lambda 및 API Gateway 시간 초과 구성을 사용하여 재시도 로직을 구현합니다.', false, 3);
INSERT INTO public.choices VALUES (744, 182, '소규모 기초 모델(FM)을 사용하여 각 문의의 복잡성을 분류하는 다단계 아키텍처를 구축합니다. 간단한 문의는 더 작고 비용 효율적인 모델로, 복잡한 문의는 더 크고 기능이 뛰어난 모델로 배정합니다. AWS Lambda 함수를 사용하여 배정 로직을 처리합니다.', false, 0);
INSERT INTO public.choices VALUES (745, 182, 'Amazon Bedrock 의 지능형 프롬프트 라우팅 기능을 사용하여 문의를 자동으로 분석합니다. 간단한 제품 문의는 더 작은 모델로, 복잡한 반품 정책 문의는 더 기능이 뛰어난 더 큰 모델로 배정합니다.', true, 1);
INSERT INTO public.choices VALUES (746, 182, '온디맨드 가격 책정을 사용하는 Amazon Bedrock 중간 크기 파운데이션 모델(FM)을 활용하는 단일 모델 솔루션을 구현합니다. 동일한 모델을 사용하여 단순 및 복잡 쿼리를 모두 처리할 수 있도록 모델 프롬프트에 특별 지침을 포함합니다.', false, 2);
INSERT INTO public.choices VALUES (747, 182, '단순 및 복잡 쿼리에 대해 별도의 Amazon Bedrock 엔드포인트를 생성합니다. 키워드 감지 기반의 규칙 기반 라우팅 시스템을 구현합니다. 작은 모델에는 온디맨드 가격 책정을, 큰 모델에는 프로비저닝된 처리량을 사용합니다.', false, 3);
INSERT INTO public.choices VALUES (748, 183, '추론 지연 시간을 안정화하기 위해 프로비저닝된 처리량으로 Amazon Bedrock 을 배포합니다. 안전하지 않은 출력을 차단하기 위해 의미론적 거부 규칙이 있는 Amazon Bedrock 가드레일을 적용합니다. A. Amazon Bedrock Prompt Management 를 사용하여 승인 워크플로를 통해 프롬프트를 관리합니다.', true, 0);
INSERT INTO public.choices VALUES (749, 183, 'Amazon Bedrock Agents 를 사용하여 체이닝을 관리합니다. 모델 입력 및 출력을 Amazon CloudWatch Logs 에 기록합니다. Amazon CloudWatch 의 로그를 사용하여 프롬프트 버전에 대한 A/B 테스트를 수행합니다.', false, 1);
INSERT INTO public.choices VALUES (750, 183, '프롬프트 결과를 Amazon ElastiCache 에 캐시합니다. AWS Lambda 함수를 사용하여 메타데이터를 사전 처리하고 엔드 투 엔드 지연 시간을 추적합니다. AWS X-Ray 를 사용하여 성능 병목 현상을 식별하고 해결합니다.', false, 2);
INSERT INTO public.choices VALUES (751, 183, 'Amazon Kendra 를 사용하여 로스팅 로그 검색 정확도를 향상합니다. 정규화된 프롬프트 메타데이터를 Amazon DynamoDB 에 저장합니다. AWS Step Functions 를 사용하여 다단계 프롬프트를 오케스트레이션합니다.', false, 3);
INSERT INTO public.choices VALUES (752, 184, '각 리전에 로컬 IAM 정책을 사용하여 애플리케이션을 배포합니다. Amazon Bedrock 의 리전 간 추론 기능을 사용하여 워크로드를 분산합니다. Amazon CloudWatch 를 사용하여 AI 의사 결정 프로세스 및 데이터 처리 활동을 로깅합니다. 리전별 규정 준수 인증을 수동으로 추적합니다.', false, 0);
INSERT INTO public.choices VALUES (753, 184, 'AWS Organizations 에서 SCP 를 사용하여 위치별 권한을 관리합니다. AWS CloudTrail 의 변경 불가능한 로그를 사용하여 의사 결정 프로세스를 감사합니다. 사용자 지정 모델을 Amazon Bedrock 으로 가져와 각 리전에 배포합니다.', false, 1);
INSERT INTO public.choices VALUES (754, 184, '리전별 S3 버킷 정책을 사용하여 Amazon S3 객체 잠금을 활용합니다. Amazon Bedrock 으로 데이터 포인트를 전송하기 전에 지리적 출처를 기준으로 해당 리전 내에서 데이터 포인트를 사전 처리합니다. Amazon Macie 를 사용하여 데이터를 분류합니다. AWS CloudTrail 의 변경 불가능한 로그를 사용하여 의사 결정 프로세스를 감사합니다.', true, 2);
INSERT INTO public.choices VALUES (755, 184, '각 리전에 대해 개별 규정 준수 프레임워크를 갖춘 별도의 AWS 계정을 생성합니다. 사용자 지정 모니터링 기능을 갖춘 Amazon SageMaker AI 를 사용하여 모델 성능 및 데이터 상주 요구 사항 준수 여부를 추적합니다. 각 규제 관할 구역에 대한 수동 보고서를 생성합니다.', false, 3);
INSERT INTO public.choices VALUES (756, 185, 'Amazon Bedrock 가드레일을 구성하여 사용자 지정 콘텐츠 필터 및 유해성 감지 기능을 적용합니다. Amazon Bedrock 모델 평가를 사용하여 오류(환상)를 감지합니다. 응답-답변 쌍을 Amazon DynamoDB 에 저장하여 감사 추적을 캡처하고 TTL 을 설정합니다. Amazon CloudWatch 사용자 지정 메트릭을 기존 규정 준수 대시보드와 통합합니다.', true, 0);
INSERT INTO public.choices VALUES (757, 185, 'Amazon Bedrock 을 배포하고 AWS PrivateLink 를 사용하여 애플리케이션에 안전하게 액세스합니다. AWS Lambda 함수를 사용하여 사용자 지정 프롬프트 유효성 검사를 구현합니다. 프롬프트-응답 쌍을 Amazon S3 버킷에 저장하고 S3 수명 주기 정책을 구성합니다. 모델 성능 지표를 모니터링하기 위해 사용자 지정 Amazon CloudWatch 대시보드를 생성합니다.', false, 1);
INSERT INTO public.choices VALUES (758, 185, 'Amazon Bedrock 에이전트와 Amazon Bedrock 지식 기반을 사용하여 응답을 검증합니다. Amazon Bedrock Guardrails 를 사용하여 콘텐츠 안전성을 강화합니다. Amazon OpenSearch Service 를 사용하여 프롬프트-응답 쌍을 저장하고 색인을 생성합니다. OpenSearch Service 를 Amazon QuickSight 와 통합하여 규정 준수 보고서를 생성하고 모델 동작 변화를 감지합니다.', false, 2);
INSERT INTO public.choices VALUES (759, 185, 'Amazon SageMaker Model Monitor 를 사용하여 모델 동작 변화를 감지합니다. AWS WAF 를 사용하여 콘텐츠를 필터링합니다. 고객 상호 작용을 암호화된 Amazon RDS 데이터베이스에 저장합니다. Amazon API Gateway 를 사용하여 규정 준수 대시보드와 통합할 사용자 지정 HTTP API 를 생성합니다.', false, 3);
INSERT INTO public.choices VALUES (760, 186, 'Amazon Bedrock 가드레일을 구성하여 사용자 지정 콘텐츠 필터 및 유해성 감지 기능을 적용합니다. Amazon Bedrock 모델 평가를 사용하여 오류(환상)를 감지합니다. 응답-답변 쌍을 Amazon DynamoDB 에 저장하여 감사 추적을 캡처하고 TTL(Time To Live)을 설정합니다. Amazon CloudWatch 사용자 지정 메트릭을 기존 규정 준수 대시보드와 통합합니다.', true, 0);
INSERT INTO public.choices VALUES (761, 186, 'Amazon Bedrock 을 배포하고 AWS PrivateLink 를 사용하여 애플리케이션에 안전하게 액세스합니다. AWS Lambda 함수를 사용하여 사용자 지정 프롬프트 유효성 검사를 구현합니다. 프롬프트-응답 쌍을 Amazon S3 버킷에 저장하고 S3 수명 주기 정책을 구성합니다. 모델 성능 지표를 모니터링하기 위해 사용자 지정 Amazon CloudWatch 대시보드를 생성합니다.', false, 1);
INSERT INTO public.choices VALUES (762, 186, 'Amazon Bedrock 에이전트와 Amazon Bedrock 지식 기반을 사용하여 응답을 검증합니다. Amazon Bedrock Guardrails 를 사용하여 콘텐츠 안전성을 강화합니다. Amazon OpenSearch Service 를 사용하여 프롬프트-응답 쌍을 저장하고 색인을 생성합니다. OpenSearch Service 를 Amazon QuickSight 와 통합하여 규정 준수 보고서를 생성하고 모델 동작 변화를 감지합니다.', false, 2);
INSERT INTO public.choices VALUES (763, 186, 'Amazon SageMaker Model Monitor 를 사용하여 모델 동작 변화를 감지합니다. AWS WAF 를 사용하여 콘텐츠를 필터링합니다. 고객 상호 작용을 암호화된 Amazon RDS 데이터베이스에 저장합니다. Amazon API Gateway 를 사용하여 규정 준수 대시보드와 통합할 사용자 지정 HTTP API 를 생성합니다.', false, 3);
INSERT INTO public.choices VALUES (764, 187, 'Amazon SageMaker 엔드포인트를 배포하여 정밀하게 조정된 순위 모델을 실행합니다. Amazon API Gateway REST API 를 사용하여 요청을 라우팅합니다. 애플리케이션이 REST API 를 통해 요청하여 결과 순위를 다시 지정하도록 구성합니다.', false, 0);
INSERT INTO public.choices VALUES (765, 187, 'Amazon Comprehend 를 사용하여 문서를 분류하고 관련성 점수를 적용합니다. RAG 애플리케이션의 재순위화 프로세스를 Amazon Textract 와 통합하여 문서 분석을 실행합니다. Amazon Neptune 을 사용하여 그래프 기반 관련성 계산을 수행합니다.', false, 1);
INSERT INTO public.choices VALUES (766, 187, 'Amazon Bedrock Knowledge Bases Retrieve API 를 사용하여 초기 문서 검색을 수행하는 검색 파이프라인을 구현합니다. Amazon Bedrock Rerank API 를 호출하여 결과를 재순위화합니다. InvokeModelWithResponseStream 작업을 호출하여 응답을 생성합니다.', false, 2);
INSERT INTO public.choices VALUES (767, 187, 'Amazon Bedrock Knowledge Bases 내의 재순위화 구성을 통해 최신 Amazon 재순위화 모델을 사용합니다. 이 모델을 사용하여 문서 관련성 점수를 개선하고 문맥 평가를 기반으로 결과를 재정렬합니다.', true, 3);
INSERT INTO public.choices VALUES (768, 188, '비동기 API 호출을 사용한 병렬 처리. 불쾌한 콘텐츠에 대한 유해성 감지. 부적절한 조언 요청에 대한 신속한 안전 분류. 개인 식별 정보(PII) 감지(수정 없이).', false, 0);
INSERT INTO public.choices VALUES (769, 188, '불쾌한 콘텐츠와 부적절한 조언 요청을 감지하는 FM 을 구축하기 위한 사용자 지정 분류. 개인 식별 정보(PII) 탐지를 메시지가 사용자 지정 분류기를 통과할 때만 보조 필터로 적용합니다.', false, 1);
INSERT INTO public.choices VALUES (770, 188, '다단계 프로세스를 배포합니다. 프로세스를 구성하여 먼저 프롬프트 안전 분류를 사용하고, 안전한 프롬프트에 대해서만 유해성 탐지를 수행한 다음, 스트리밍 모드에서 개인 식별 정보(PII) 탐지를 수행합니다. 플래그가 지정된 메시지는 사람이 검토할 수 있도록 Amazon EventBridge 를 통해 전달합니다.', false, 2);
INSERT INTO public.choices VALUES (771, 188, '모든 범주에 대해 임계값을 0.5 로 구성하여 유해성 탐지를 사용합니다. 프롬프트 안전 분류와 개인 식별 정보(PII) 탐지 모두에 대해 엔티티 마스킹을 적용하여 병렬 처리를 사용합니다. Amazon CloudWatch 알람을 적용하여 메트릭을 필터링합니다.', true, 3);
INSERT INTO public.choices VALUES (772, 189, 'Amazon Bedrock Knowledge Bases 를 사용하여 RAG 아키텍처를 구현하고 고객 여행 이력 데이터를 분석하여 애플리케이션에 시맨틱 검색 기능을 제공합니다. 시맨틱 검색 기능을 활용하여 관련 예약 패턴, 선호도 및 로열티 정보를 검색하고 개인화된 좌석 등급 업그레이드 추천을 생성합니다. Amazon Bedrock 가드레일을 적용하여 콘텐츠를 필터링합니다. AWS Step Functions 및 AWS Lambda 함수를 사용하여 유효성 검사 워크플로를 오케스트레이션하여 오류를 줄입니다.', false, 0);
INSERT INTO public.choices VALUES (773, 189, 'RDS 데이터베이스에서 관련 예약 패턴, 선호도 및 로열티 정보를 정확하게 검색하기 위해 SQL 유효성 검사를 포함한 텍스트-SQL 변환을 구현합니다. 검색 결과를 사용하여 개인 맞춤형 객실 업그레이드 추천을 생성합니다. Amazon Bedrock 가이드라인을 적용하여 콘텐츠를 필터링합니다. AWS Step Functions 및 AWS Lambda 함수를 사용하여 유효성 검사 워크플로를 오케스트레이션하고 오류를 줄입니다.', false, 1);
INSERT INTO public.choices VALUES (774, 189, 'Amazon OpenSearch Service 를 사용하여 고객 여행 이력 임베딩에 대한 벡터 검색을 구현합니다. 벡터 검색을 통해 애플리케이션이 예약 패턴, 선호도 및 로열티 정보를 유사도 기반으로 검색하여 개인 맞춤형 객실 업그레이드 추천을 생성할 수 있도록 합니다. Amazon Bedrock 가이드라인을 적용하여 응답을 필터링합니다. 신뢰도 점수 및 의미 유사도 검색을 사용하여 오류를 줄입니다.', false, 2);
INSERT INTO public.choices VALUES (775, 189, 'RDS 데이터베이스에서 관련 예약 패턴, 선호도 및 로열티 정보를 정확하게 검색하기 위해 SQL 유효성 검사를 포함한 텍스트-SQL 변환을 구현합니다. 검색 결과를 사용하여 개인 맞춤형 객실 업그레이드 추천을 생성합니다. Amazon Bedrock 가이드라인을 적용하여 응답을 필터링합니다. 신뢰도 점수 및 의미 유사도 검색을 사용하여 오류를 줄입니다.', true, 3);
INSERT INTO public.choices VALUES (776, 190, '민감한 정보 필터를 적용하도록 리전 간 Amazon Bedrock 가드레일을 구성합니다. 개발 및 테스트 단계에서는 가드레일을 감지 모드로 설정하고, 프로덕션 배포 시에는 차단 모드로 전환합니다.', false, 0);
INSERT INTO public.choices VALUES (777, 190, '민감한 정보 필터를 적용하도록 Amazon Bedrock 가드레일을 구성합니다. 개발 및 테스트 단계에서는 가드레일을 마스크 모드로 설정하고, 프로덕션 배포 시에는 차단 모드로 전환합니다. 회사가 운영하는 각 리전에 가드레일 사본을 배포합니다.', true, 1);
INSERT INTO public.choices VALUES (778, 190, '콘텐츠 및 토픽 필터를 적용하도록 Amazon Bedrock 가드레일을 구성합니다. 개발, 테스트 및 프로덕션 단계에서는 가드레일을 감지 모드로 설정합니다. Amazon Bedrock 모델에 대한 호출 로깅을 비활성화합니다.', false, 2);
INSERT INTO public.choices VALUES (779, 190, '콘텐츠 및 단어 필터 세트를 적용하도록 교차 리전 Amazon Bedrock 가드레일을 구성합니다. 개발 및 테스트 중에는 가드레일을 감지 모드로 설정하고, 프로덕션 배포 시에는 마스크 모드로 전환합니다.', false, 3);
INSERT INTO public.choices VALUES (780, 191, 'Amazon Bedrock 의 Amazon Titan Embeddings 를 사용하여 디지털화된 파일의 벡터 표현을 생성합니다. 생성된 임베딩을 Amazon OpenSearch Service 용 OpenSearch Neural Plugin 에 저장합니다.', false, 0);
INSERT INTO public.choices VALUES (781, 191, 'Amazon Comprehend 를 사용하여 디지털화된 파일에서 주제를 추출합니다. 토픽과 파일 메타데이터를 Amazon Aurora PostgreSQL 데이터베이스에 저장합니다. Aurora 데이터베이스의 데이터를 대상으로 추상 메타데이터를 쿼리합니다.', false, 1);
INSERT INTO public.choices VALUES (782, 191, 'Amazon SageMaker AI 를 사용하여 문장 변환기 모델을 배포합니다. 이 모델을 사용하여 디지털화된 파일의 벡터 표현을 생성합니다. 생성된 임베딩을 pgvector 확장자를 가진 Amazon Aurora PostgreSQL 데이터베이스에 저장합니다.', false, 2);
INSERT INTO public.choices VALUES (783, 191, 'Amazon Bedrock 의 Amazon Titan Embeddings 를 사용하여 디지털화된 파일의 벡터 표현을 생성합니다. 생성된 임베딩을 pgvector 확장자를 가진 Amazon Aurora PostgreSQL 서버리스 데이터베이스에 저장합니다.', true, 3);
INSERT INTO public.choices VALUES (784, 192, 'AWS Step Functions 를 사용하여 녹음 파일을 처리하는 워크플로를 구성합니다. Amazon Transcribe 를 호출하여 오디오를 텍스트로 변환하고, 작업 완료를 검증하고, Amazon Bedrock FM 을 사용하여 텍스트를 처리하고 구조화된 분석 결과를 생성하는 AWS Lambda 함수를 호출하는 단계를 구성합니다.', false, 0);
INSERT INTO public.choices VALUES (785, 192, 'AWS Step Functions 를 사용하여 녹음 파일을 처리하는 워크플로를 구성합니다. Amazon Transcribe 를 호출하여 오디오를 텍스트로 변환하고, 작업 완료를 검증하고, Amazon Bedrock FM 을 직접 호출하여 JSON 형식으로 요약 및 감정 분석 결과를 생성하는 단계를 구성합니다.', true, 1);
INSERT INTO public.choices VALUES (786, 192, 'AWS Step Functions 를 사용하여 녹음 파일을 처리하는 워크플로를 구성합니다. 오디오를 텍스트로 변환하기 위해 Amazon Transcribe 를 호출하고, 작업 완료 여부를 검증하고, 구조화된 분석 결과를 생성하기 위해 Amazon Bedrock FM 을 호출하는 프롬프트를 생성하는 AWS Lambda 함수를 호출하는 단계를 구성합니다.', false, 2);
INSERT INTO public.choices VALUES (787, 192, '소스 S3 버킷에서 Amazon EventBridge 로 이벤트를 전송하도록 구성합니다. 버킷에 객체가 생성될 때 Step Functions 워크플로를 호출하는 EventBridge 규칙을 생성합니다.', true, 3);
INSERT INTO public.choices VALUES (788, 192, '소스 S3 버킷에서 객체가 생성될 때 Step Functions 워크플로로 알림을 전송하도록 구성합니다.', false, 4);
INSERT INTO public.choices VALUES (789, 193, 'S3 버킷에서 Amazon Macie PII 감지 기능을 활성화합니다. S3 트리거를 사용하여 보고서에서 PII 를 삭제하는 AWS Lambda 함수를 호출합니다. Lambda 함수가 버킷에서 오래된 문서를 삭제하고 지식 베이스 동기화를 수행하도록 구성합니다.', false, 0);
INSERT INTO public.choices VALUES (790, 193, '새 보고서가 버킷에 업로드될 때 AWS Lambda 함수를 호출하여 S3 버킷과 지식 베이스를 동기화합니다. 두 번째 Lambda 함수를 사용하여 Amazon Comprehend 를 호출하여 사용자가 엔지니어 Cognito 사용자 그룹에 속하는 경우 개인 식별 정보(PII)를 감지하고 수정합니다. S3 수명 주기 구성을 설정하여 버킷에서 3 년 이상 된 보고서를 삭제합니다.', false, 1);
INSERT INTO public.choices VALUES (791, 193, '버킷에 S3 수명 주기 구성을 설정하여 3 년 이상 된 보고서를 삭제합니다. AWS Lambda 함수를 예약하여 버킷과 지식 기반 간의 일일 동기화를 실행합니다. 사용자가 AI 어시스턴트와 상호 작용할 때 사용자의 Cognito 사용자 그룹과 일치하는 ApplyGuardrail 구성을 호출하여 필요한 경우 에이전트 응답에서 PII 를 수정합니다.', true, 2);
INSERT INTO public.choices VALUES (792, 193, '두 번째 지식 기반을 생성합니다. 버킷에 S3 수명 주기 구성을 설정하여 3 년 이상 된 보고서를 삭제합니다. 새 보고서가 버킷에 업로드될 때 버킷을 원래 지식 기반과 동기화하는 AWS Lambda 함수를 호출합니다. 두 번째 지식 기반과 버킷을 동기화하기 전에 Amazon Comprehend 를 사용하여 PII 를 감지하고 수정합니다. 사용자가 AI 어시스턴트와 상호 작용할 때, 사용자의 Cognito 사용자 그룹에 따라 모델을 적절한 지식 기반으로 리디렉션합니다.', false, 3);
INSERT INTO public.choices VALUES (793, 194, '기술 지표와 가져온 비즈니스 지표를 포함하는 CloudWatch 대시보드를 생성합니다. 기술 데이터와 비즈니스 데이터를 결합하는 CloudWatch 복합 알람을 구성합니다. Amazon SNS 를 사용하여 이해관계자에게 알림을 설정합니다.', false, 0);
INSERT INTO public.choices VALUES (794, 194, 'Amazon Managed Grafana 를 사용하여 CloudWatch 의 기술 지표와 외부 소스의 비즈니스 지표를 시각화합니다. Amazon Managed Grafana 알림을 구성하여 AWS Lambda 함수를 호출합니다. Lambda 함수가 지표가 사전 정의된 임계값을 초과할 경우 문제를 자동으로 해결하도록 구성합니다.', false, 1);
INSERT INTO public.choices VALUES (795, 194, 'CloudWatch 메트릭 스트림을 사용하여 CloudWatch 메트릭을 Amazon S3 로 스트리밍합니다. Amazon QuickSight 대시보드를 생성하여 결합된 기술 메트릭과 비즈니스 메트릭을 시각화합니다. Amazon EventBridge 규칙을 설정하여 메트릭이 사전 정의된 임계값을 초과할 때 이해 관계자에게 알림을 보냅니다.', false, 2);
INSERT INTO public.choices VALUES (796, 194, '가져온 비즈니스 메트릭과 운영 메트릭을 통합하는 CloudWatch 사용자 지정 대시보드를 구성합니다. 이상 감지 기능을 갖춘 CloudWatch 복합 알람을 설정합니다. Amazon SNS 를 사용하여 상관 관계가 있는 메트릭에서 성능 문제가 나타날 때 이해 관계자에게 알림을 보내는 알람 작업을 생성합니다.', true, 3);
INSERT INTO public.choices VALUES (797, 195, 'eu-north-1 리전의 VPC 에 노출되는 프라이빗 Amazon API Gateway REST API 를 통해 AWS Lambda 함수를 배포합니다. eu-central-1 및 eu-west-3 리전에 선택한 FM 에 대한 VPC 엔드포인트를 생성합니다. 기존 SCP 를 확장하여 직원들이 FM 을 사용할 수 있도록 합니다. REST API 를 비즈니스 애플리케이션과 통합합니다.', false, 0);
INSERT INTO public.choices VALUES (798, 195, 'eu-north-1 지역의 Amazon EC2 인스턴스에 FM 을 배포합니다. EC2 인스턴스 앞에 비공개 Amazon API Gateway REST API 를 배포합니다. Amazon Bedrock VPC 엔드포인트를 구성합니다. REST API 를 비즈니스 애플리케이션과 통합합니다.', false, 1);
INSERT INTO public.choices VALUES (799, 195, '모든 호출이 유럽 내에서 이루어지도록 eu.amazon.* 엔드포인트를 통해 교차 리전 추론을 사용하도록 FM 을 구성합니다. Amazon Bedrock VPC 엔드포인트를 구성합니다. FM 을 사용할 수 있는 유럽 기반 리전에서 추론 프로필을 통해 직원들이 FM 을 사용할 수 있도록 기존 SCP 를 확장합니다. 추론 프로필을 사용하여 Amazon Bedrock 을 비즈니스 애플리케이션과 통합합니다.', true, 2);
INSERT INTO public.choices VALUES (800, 195, 'eu-north-1 지역의 Amazon SageMaker AI 에 FM 을 배포합니다. SageMaker AI VPC 엔드포인트를 구성합니다. 직원들이 SageMaker AI 엔드포인트를 사용할 수 있도록 기존 SCP 를 확장합니다. SageMaker AI 의 FM 을 비즈니스 애플리케이션과 통합합니다.', false, 3);
INSERT INTO public.choices VALUES (801, 196, 'Amazon API Gateway 를 사용하여 들어오는 질의를 Amazon Bedrock 에이전트로 라우팅합니다. 에이전트가 질의 분해에는 Anthropic Claude 모델을, 질의 확장에는 Amazon Titan 모델을 사용하도록 구성합니다. 참조 의료 문서를 저장할 Amazon Bedrock 지식 베이스를 생성합니다.', false, 0);
INSERT INTO public.choices VALUES (802, 196, '참조 의료 문서를 저장할 Amazon Bedrock 지식 베이스를 구성합니다. 지식 베이스에서 질의 분해 기능을 활성화합니다. 애플리케이션을 지원하기 위해 기초 모델(FM)과 지식 베이스를 사용하는 Amazon Bedrock 플로우를 구성합니다.', true, 1);
INSERT INTO public.choices VALUES (803, 196, 'Amazon SageMaker AI 를 사용하여 질의 분해 및 질의 확장을 위한 사용자 지정 머신러닝 모델을 호스팅합니다. 참조 의료 문서를 저장하도록 Amazon Bedrock 지식 베이스를 구성합니다. 지식 베이스에 저장된 문서를 암호화합니다.', false, 2);
INSERT INTO public.choices VALUES (804, 196, '쿼리를 분해하기 위해 여러 AWS Lambda 함수를 오케스트레이션하는 Amazon Bedrock 에이전트를 생성합니다. 참조 의료 문서를 저장할 Amazon Bedrock 지식 베이스를 생성합니다. 에이전트의 내장 지식 베이스 기능을 사용합니다. 의료 용어의 모호성을 줄이기 위해 에이전트에 심층적인 검색 및 추론 기능을 추가합니다.', false, 3);


